1	/**
2	 * Auxilio Visitor — Google Calendar add-on (card-first).
3	 *
4	 * The whole host flow lives in this card; it calls office-ops-engine over HTTPS.
5	 * Engine contract: ../office-ops-engine/spec/2026-06-16_calendar_addon_register_endpoint.md
6	 *
7	 * Apps Script (GAS, V8) — flat global scope, no imports/modules.
8	 * First version: push with clasp, then refine in the Apps Script editor (it can run
9	 * and log there; it can't be run from the monorepo).
10	 */
11	
12	// Engine base URL. Default = the local-tunnel domain (npm run backendtunnel).
13	// Must also be listed in appsscript.json → urlFetchWhitelist.
14	var ENGINE_BASE = 'https://unyearning-olympia-unclimactic.ngrok-free.dev';
15	
16	// Appointy logo embedded as a base64 data URI (gradient original from appointy.svg).
17	// Source: appointy.svg (copied from visitor-web/public/, also in this repo).
18	// Used by setImageUrl() in all card headers.
19	var ADDON_ICON_URL = 'data:image/svg+xml;base64,REDACTED';
20	
21	// Primary brand colour — used for filled buttons and accent text.
22	var BRAND_COLOR = '#92288E';
23	
24	// ── Triggers ──────────────────────────────────────────────
25	function onCalendarEventOpen(e) { return [buildVisitorCard_(e)]; }
26	function onCalendarEventUpdate(e) { return [buildVisitorCard_(e)]; }
27	
28	// Serves the branded icon SVG at ?asset=logo. ContentService.MimeType.XML is the
29	// closest available type to image/svg+xml in GAS. The manifest logoUrl below points
30	// to visitor-web instead, which nginx serves with the correct image/svg+xml header.
31	function doGet(e) {
32	  if (e && e.parameter && e.parameter.asset === 'logo') {
33	    var b64 = ADDON_ICON_URL.split(',')[1];
34	    var svgText = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
35	    return ContentService.createTextOutput(svgText).setMimeType(ContentService.MimeType.XML);
36	  }
37	  return ContentService.createTextOutput('Auxilio Workspace Add-on');
38	}
39	
40	// Three-dot menu → Sign out.
41	// NOTE: we deliberately do NOT call ScriptApp.invalidateAuth() — invalidating auth
42	// breaks every subsequent add-on invocation (incl. re-clicking this very item) with
43	// "Unspecified error invoking the add-on", because the platform can't run any
44	// function once authorization is cleared. A Calendar add-on also has no login page
45	// we can navigate to (Google only shows the consent prompt automatically on the next
46	// authorized open). So sign-out routes the user to the real, linkable destination:
47	// the Google Account permissions page, where they can remove access / switch account.
48	// Removing access there forces full re-consent the next time they open the add-on.
49	function onSignOut(e) {
50	  var card = CardService.newCardBuilder()
51	    .setHeader(CardService.newCardHeader()
52	      .setTitle('Sign out')
53	      .setImageUrl(ADDON_ICON_URL))
54	    .addSection(CardService.newCardSection()
55	      .addWidget(CardService.newDecoratedText()
56	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
57	        .setText('Switch account or re-grant access')
58	        .setBottomLabel('Remove Auxilio Visitor from your Google account, then reopen the add-on — you\'ll be asked to sign in and grant access again.')
59	        .setWrapText(true))
60	      .addWidget(CardService.newTextButton()
61	        .setText('Manage access')
62	        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
63	        .setOpenLink(CardService.newOpenLink()
64	          .setUrl('https://myaccount.google.com/permissions'))))
65	    .build();
66	  return CardService.newUniversalActionResponseBuilder()
67	    .displayAddOnCards([card])
68	    .build();
69	}
70	
71	function onHomepage(e) {
72	  var introSection = CardService.newCardSection()
73	    .addWidget(CardService.newTextParagraph()
74	      .setText('Open a calendar event with external guests to register visitor passes.'));
75	
76	  var howSection = CardService.newCardSection()
77	    .setHeader('How it works')
78	    .addWidget(CardService.newDecoratedText()
79	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
80	      .setText('Choose who gets a pass')
81	      .setBottomLabel('Toggle guests on or off from the event\'s attendee list.')
82	      .setWrapText(true))
83	    .addWidget(CardService.newDecoratedText()
84	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
85	      .setText('Review and send')
86	      .setBottomLabel('Edit names and phone numbers, preview the invite email, then send.')
87	      .setWrapText(true))
88	    .addWidget(CardService.newDecoratedText()
89	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.TICKET))
90	      .setText('Manage anytime')
91	      .setBottomLabel('Cancel or resend passes by toggling them off and on.')
92	      .setWrapText(true));
93	
94	  return CardService.newCardBuilder()
95	    .setHeader(CardService.newCardHeader()
96	      .setTitle('Auxilio Visitor')
97	      .setSubtitle('Visitor passes from your calendar')
98	      .setImageUrl(ADDON_ICON_URL))
99	    .addSection(introSection)
100	    .addSection(howSection)
101	    .build();
102	}
103	
104	// ── Engine HTTP ───────────────────────────────────────────
105	function engineFetch_(path, method, payload) {
106	  var options = {
107	    method: method,
108	    contentType: 'application/json',
109	    muteHttpExceptions: true,
110	    headers: {
111	      Authorization: 'Bearer ' + ScriptApp.getIdentityToken(),
112	      'ngrok-skip-browser-warning': 'true'
113	    }
114	  };
115	  if (payload) options.payload = JSON.stringify(payload);
116	  var res = UrlFetchApp.fetch(ENGINE_BASE + path, options);
117	  var json = {};
118	  try { json = JSON.parse(res.getContentText()); } catch (err) {}
119	  return { code: res.getResponseCode(), json: json };
120	}
121	
122	// Resolve attendees + (best-effort) iCalUID/title/times for the open event.
123	// Attendees come from the add-on payload (currentEventAccess) — no API call needed.
124	// The Calendar API lookup enriches with the canonical iCalUID + title/times so the
125	// engine dedups with the .ics/OAuth paths; if it fails we fall back to the event id
126	// as the key so the flow still works.
127	function loadEvent_(e) {
128	  var cal = e.calendar || {};
129	  var calendarId = cal.calendarId;
130	  var eventId = cal.id;
131	  var payloadAtt = cal.attendees || [];
132	  var info = {
133	    iCalUid: eventId,
134	    providerEventId: eventId,
135	    keySource: 'eventId',
136	    title: '',
137	    start: null,
138	    end: null,
139	    attendees: mapAttendees_(payloadAtt),
140	    debug: ''
141	  };
142	  var ev = fetchEventWithRetry_(calendarId, eventId);
143	  if (ev) {
144	    if (ev.iCalUID) { info.iCalUid = ev.iCalUID; info.keySource = 'iCalUID'; }
145	    info.title = ev.summary || '';
146	    info.start = ev.start ? (ev.start.dateTime || ev.start.date) : null;
147	    info.end = ev.end ? (ev.end.dateTime || ev.end.date) : null;
148	    var apiAtt = mapAttendees_(ev.attendees);
149	    if (info.attendees.length === 0 && apiAtt.length > 0) info.attendees = apiAtt;
150	  }
151	  info.debug = 'key=' + info.keySource + ' guests=' + info.attendees.length;
152	  return info;
153	}
154	
155	// Resolve the event from the Calendar API, tolerating transient 404s: retry once
156	// after a short wait (eventual consistency) and try the primary calendar as a
157	// fallback for the calendarId. Returns the event resource or null.
158	function fetchEventWithRetry_(calendarId, eventId) {
159	  var targets = [];
160	  if (calendarId) targets.push(calendarId);
161	  if (calendarId !== 'primary') targets.push('primary');
162	  for (var attempt = 0; attempt < 2; attempt++) {
163	    for (var t = 0; t < targets.length; t++) {
164	      try {
165	        var ev = Calendar.Events.get(targets[t], eventId);
166	        if (ev) return ev;
167	      } catch (err) {
168	        // 404 / transient → fall through to the next target / retry.
169	      }
170	    }
171	    if (attempt === 0) Utilities.sleep(500);
172	  }
173	  return null;
174	}
175	
176	// Per-guest avatar: Gravatar keyed on the email (real photo if they have one),
177	// falling back to a coloured initials avatar (ui-avatars) when they don't. Rendered
178	// as a circular image icon. Image URLs are fetched by Google's client, so they
179	// don't need urlFetchWhitelist.
180	function avatarIcon_(email, name) {
181	  var initials = (name || email || '?').trim().charAt(0).toUpperCase() || '?';
182	  var fallback = 'https://ui-avatars.com/api/?name=' + encodeURIComponent(initials) +
183	    '&size=64&background=92288E&color=ffffff&bold=true';
184	  var url = 'https://www.gravatar.com/avatar/' + md5Hex_((email || '').trim().toLowerCase()) +
185	    '?s=64&d=' + encodeURIComponent(fallback);
186	  return CardService.newIconImage()
187	    .setIconUrl(url)
188	    .setImageCropType(CardService.ImageCropType.CIRCLE);
189	}
190	
191	// Minimal MD5 → lowercase hex (Gravatar needs MD5 of the email).
192	function md5Hex_(str) {
193	  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, str, Utilities.Charset.UTF_8);
194	  var hex = '';
195	  for (var i = 0; i < bytes.length; i++) {
196	    var b = (bytes[i] + 256) % 256;
197	    hex += (b < 16 ? '0' : '') + b.toString(16);
198	  }
199	  return hex;
200	}
201	
202	function mapAttendees_(list) {
203	  return (list || [])
204	    .filter(function (a) { return a && a.email && !a.self && !a.organizer && !a.resource; })
205	    .map(function (a) {
206	      // Google often sets displayName = the email for non-contacts → treat as no name.
207	      var nm = (a.displayName && a.displayName !== a.email) ? a.displayName : '';
208	      return { email: a.email, name: nm };
209	    });
210	}
211	
212	// ── Card helpers ──────────────────────────────────────────
213	
214	function statusLabel_(g) {
215	  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
216	  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled — toggle on to resend</font>';
217	  return g.include === false
218	    ? '<font color="#9aa0a6">No pass</font>'
219	    : '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
220	}
221	
222	// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
223	function buildStatLine_(roster) {
224	  var total = roster.length;
225	  var sent = 0, pending = 0, cancelled = 0;
226	  for (var i = 0; i < roster.length; i++) {
227	    var g = roster[i];
228	    if (g.status === 'sent') sent++;
229	    else if (g.status === 'cancelled') cancelled++;
230	    else if (g.include !== false) pending++;
231	  }
232	  var parts = [total + (total === 1 ? ' guest' : ' guests')];
233	  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
234	  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
235	  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
236	  return parts.join('  ·  ');
237	}
238	
239	// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
240	function formatEventSubtitle_(ev) {
241	  if (!ev.start) return ev.title || '';
242	  try {
243	    var d = new Date(ev.start);
244	    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
245	    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
246	    var datePart = day + ', ' + time;
247	    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
248	  } catch (err) {
249	    return ev.title || '';
250	  }
251	}
252	
253	// ── Main card ─────────────────────────────────────────────
254	function buildVisitorCard_(e) {
255	  // Fast path: no external guests in the payload → render immediately without any
256	  // network call. Keeps empty events snappy so the loader never lingers.
257	  var cal = e.calendar || {};
258	  if (mapAttendees_(cal.attendees).length === 0) {
259	    return CardService.newCardBuilder()
260	      .setHeader(CardService.newCardHeader()
261	        .setTitle('Visitor passes')
262	        .setImageUrl(ADDON_ICON_URL))
263	      .addSection(CardService.newCardSection()
264	        .addWidget(CardService.newDecoratedText()
265	          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
266	          .setText('No guests yet')
267	          .setBottomLabel('Add a guest to this event.')
268	          .setWrapText(true)))
269	      .build();
270	  }
271	
272	  var ev = loadEvent_(e);
273	  if (!ev.iCalUid) return errorCard_('No event id in payload (' + ev.debug + ') — save the event, then reopen.');
274	
275	  var organizerEmail = (cal.organizer && cal.organizer.email) || '';
276	  var res = engineFetch_('/api/visitor/calendar/addon/draft', 'POST', {
277	    iCalUid: ev.iCalUid, providerEventId: ev.providerEventId, organizerEmail: organizerEmail,
278	    title: ev.title, start: ev.start, end: ev.end, attendees: ev.attendees
279	  });
280	  if (res.code === 401) return errorCard_('Not authorized. Check the engine\'s AUXILIO_WORKSPACE_OAUTH_CLIENT_ID.');
281	  if (res.code === 403) return errorCard_('Your domain is not allowed to host visits.');
282	  if (res.code !== 200) return errorCard_('Engine error ' + res.code + '. Try refreshing the page.');
283	
284	  var draft = res.json;
285	  var roster = draft.roster || [];
286	  resolveAndStoreNames_(ev.iCalUid, roster);
287	  var managed = !!draft.materialized;
288	
289	  var card = CardService.newCardBuilder()
290	    .setHeader(CardService.newCardHeader()
291	      .setTitle(managed ? 'Manage passes' : 'Visitor passes')
292	      .setSubtitle(formatEventSubtitle_(ev))
293	      .setImageUrl(ADDON_ICON_URL));
294	
295	  if (roster.length === 0) {
296	    return card
297	      .addSection(CardService.newCardSection()
298	        .addWidget(CardService.newDecoratedText()
299	          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
300	          .setText('No guests yet')
301	          .setBottomLabel('Add a guest to this event.')
302	          .setWrapText(true)))
303	      .build();
304	  }
305	
306	  // Stat summary at the top (non-collapsible)
307	  card.addSection(CardService.newCardSection()
308	    .addWidget(CardService.newTextParagraph().setText(buildStatLine_(roster))));
309	
310	  // One collapsible section per guest. The toggle row is always visible;
311	  // name + phone inputs collapse under it to keep long rosters scannable.
312	  var emails = [];
313	  for (var i = 0; i < roster.length; i++) {
314	    var g = roster[i];
315	    emails.push(g.email);
316	
317	    var mainText   = g.name || g.email;
318	    var bottomText = g.name
319	      ? (g.email + '  ·  ' + statusLabel_(g))
320	      : statusLabel_(g);
321	
322	    var sw = CardService.newSwitch()
323	      .setFieldName('inc_' + g.email)
324	      .setValue('on')
325	      .setSelected(g.include !== false);
326	
327	    var guestSection = CardService.newCardSection()
328	      .setCollapsible(true)
329	      .setNumUncollapsibleWidgets(1)
330	      // ── Toggle row — always visible ──────────────────
331	      .addWidget(CardService.newDecoratedText()
332	        .setStartIcon(avatarIcon_(g.email, g.name))
333	        .setText(mainText)
334	        .setBottomLabel(bottomText)
335	        .setWrapText(true)
336	        .setSwitchControl(sw))
337	      // ── Name input — collapses ───────────────────────
338	      .addWidget(CardService.newTextInput()
339	        .setFieldName('name_' + g.email)
340	        .setTitle('Full name')
341	        .setValue(g.name || ''))
342	      // ── Phone label with icon — collapses ───────────
343	      .addWidget(CardService.newDecoratedText()
344	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PHONE))
345	        .setText('Phone number')
346	        .setWrapText(true))
347	      // ── Phone input — collapses ──────────────────────
348	      .addWidget(CardService.newTextInput()
349	        .setFieldName('phone_' + g.email)
350	        .setTitle('Phone')
351	        .setValue(g.phone || ''));
352	
353	    card.addSection(guestSection);
354	  }
355	
356	  var params = { iCalUid: ev.iCalUid, emails: emails.join(',') };
357	  addCalendarSyncSection_(card, draft.calendarSync);
358	
359	  // Primary CTA pinned to the footer — always reachable without scrolling.
360	  card.setFixedFooter(CardService.newFixedFooter()
361	    .setPrimaryButton(CardService.newTextButton()
362	      .setText(managed ? 'Update passes' : 'Send passes')
363	      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
364	      .setBackgroundColor(BRAND_COLOR)
365	      .setOnClickAction(CardService.newAction()
366	        .setFunctionName('onReviewSend')
367	        .setParameters(params)))
368	    .setSecondaryButton(CardService.newTextButton()
369	      .setText('Preview email')
370	      .setOnClickAction(CardService.newAction()
371	        .setFunctionName('onPreview')
372	        .setParameters(params))));
373	
374	  return card.build();
375	}
376	
377	// Background auto-sync (move/delete) status. Only rendered when the host owns the event.
378	function addCalendarSyncSection_(card, sync) {
379	  if (!sync || !sync.relevant) return;
380	  var section = CardService.newCardSection();
381	  if (sync.connected) {
382	    section.addWidget(CardService.newDecoratedText()
383	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.STAR))
384	      .setText('Auto-sync is on')
385	      .setBottomLabel('Move or cancel this meeting and passes update automatically.')
386	      .setWrapText(true));
387	  } else if (sync.connectUrl) {
388	    section
389	      .addWidget(CardService.newDecoratedText()
390	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.CLOCK))
391	        .setText('Keep passes in sync')
392	        .setBottomLabel('Connect your calendar so moving or cancelling this meeting updates passes automatically — even when this panel is closed.')
393	        .setWrapText(true))
394	      .addWidget(CardService.newTextButton()
395	        .setText('Connect calendar')
396	        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
397	        .setBackgroundColor(BRAND_COLOR)
398	        .setOpenLink(CardService.newOpenLink()
399	          .setUrl(sync.connectUrl)
400	          .setOpenAs(CardService.OpenAs.OVERLAY)));
401	  }
402	  card.addSection(section);
403	}
404	
405	// ── Actions ───────────────────────────────────────────────
406	// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
407	function cardDeriveName_(email) {
408	  var local = (email.split('@')[0] || email);
409	  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
410	}
411	
412	var _peopleWarmed = false;
413	function peopleSearch_(path, email) {
414	  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
415	  var base = 'https://people.googleapis.com/v1/';
416	  // searchContacts/otherContacts.search require a warmup (empty-query) call first.
417	  if (!_peopleWarmed) {
418	    UrlFetchApp.fetch(base + 'people:searchContacts?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
419	    UrlFetchApp.fetch(base + 'otherContacts:search?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
420	    _peopleWarmed = true;
421	    Utilities.sleep(200);
422	  }
423	  var url = base + path + '?query=' + encodeURIComponent(email) + '&readMask=names,emailAddresses';
424	  var resp = UrlFetchApp.fetch(url, { headers: headers, muteHttpExceptions: true });
425	  if (resp.getResponseCode() !== 200) return '';
426	  var results = (JSON.parse(resp.getContentText()).results) || [];
427	  for (var i = 0; i < results.length; i++) {
428	    var person = results[i].person || {};
429	    var emails = person.emailAddresses || [];
430	    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
431	    if (match && person.names && person.names.length) return person.names[0].displayName || '';
432	  }
433	  return '';
434	}
435	
436	function resolveContactName_(email) {
437	  try {
438	    return peopleSearch_('people:searchContacts', email) || peopleSearch_('otherContacts:search', email);
439	  } catch (err) {
440	    return '';
441	  }
442	}
443	
444	// For each guest whose name is still auto-derived, look up the real contact name
445	// and PATCH it onto the draft (so subsequent opens skip the lookup). Mutates roster.
446	function resolveAndStoreNames_(iCalUid, roster) {
447	  var patches = [];
448	  for (var i = 0; i < roster.length; i++) {
449	    var g = roster[i];
450	    var looksDerived = !g.name || g.name === cardDeriveName_(g.email);
451	    if (!looksDerived) continue;
452	    var resolved = resolveContactName_(g.email);
453	    if (resolved && resolved !== g.name) {
454	      g.name = resolved;                       // reflect immediately in this render
455	      patches.push({ email: g.email, name: resolved });
456	    }
457	  }
458	  if (patches.length) {
459	    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
460	  }
461	}
462	
463	// Review step: persist edits, then push a textual confirm card. Cards can't
464	// render HTML inline (that's the "Preview email" overlay link), so the review
465	// here is the recipient list + what will happen — the guard before sending.
466	function onReviewSend(e) {
467	  var iCalUid = e.parameters.iCalUid;
468	  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
469	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
470	  var inputs = formInputs_(e);
471	  var included = [];
472	  var excluded = [];
473	  for (var i = 0; i < emails.length; i++) {
474	    var em = emails[i];
475	    var on = formValue_(inputs['inc_' + em]) === 'on';
476	    var name = formValue_(inputs['name_' + em]) || em;
477	    (on ? included : excluded).push({ email: em, name: name });
478	  }
479	  if (!included.length) return notify_('Turn on at least one guest before sending.');
480	  return CardService.newActionResponseBuilder()
481	    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
482	    .build();
483	}
484	
485	function buildConfirmCard_(params, included, excluded) {
486	  var card = CardService.newCardBuilder()
487	    .setHeader(CardService.newCardHeader()
488	      .setTitle('Send ' + included.length + ' pass' + (included.length > 1 ? 'es' : '') + '?')
489	      .setImageUrl(ADDON_ICON_URL));
490	  var sec = CardService.newCardSection().setHeader('These guests get a pass');
491	  for (var i = 0; i < included.length; i++) {
492	    sec.addWidget(CardService.newDecoratedText()
493	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
494	      .setText(included[i].name)
495	      .setBottomLabel(included[i].email)
496	      .setWrapText(true));
497	  }
498	  card.addSection(sec);
499	  if (excluded.length) {
500	    var ex = CardService.newCardSection().setHeader('Skipped (no pass / cancelled if sent before)');
501	    for (var j = 0; j < excluded.length; j++) {
502	      ex.addWidget(CardService.newDecoratedText()
503	        .setText(excluded[j].name).setBottomLabel(excluded[j].email).setWrapText(true));
504	    }
505	    card.addSection(ex);
506	  }
507	  card.setFixedFooter(CardService.newFixedFooter()
508	    .setPrimaryButton(CardService.newTextButton()
509	      .setText('Send passes')
510	      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
511	      .setBackgroundColor(BRAND_COLOR)
512	      .setOnClickAction(CardService.newAction().setFunctionName('onSaveAndSend').setParameters(params)))
513	    .setSecondaryButton(CardService.newTextButton()
514	      .setText('Back')
515	      .setOnClickAction(CardService.newAction().setFunctionName('onConfirmBack').setParameters(params))));
516	  return card.build();
517	}
518	
519	function onConfirmBack(e) {
520	  return CardService.newActionResponseBuilder()
521	    .setNavigation(CardService.newNavigation().popCard())
522	    .build();
523	}
524	
525	function onSaveAndSend(e) {
526	  var iCalUid = e.parameters.iCalUid;
527	  patchFromForm_(iCalUid, e);                       // persist toggles/name/phone first
528	  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', { iCalUid: iCalUid });
529	  var msg;
530	  if (res.code === 200) {
531	    var sent = (res.json.created || []).length;
532	    var cancelled = (res.json.cancelled || []).length;
533	    var failed = res.json.failed || [];
534	    if (failed.length) {
535	      // Surface WHY a pass couldn't be sent (most often: event time in the past)
536	      // instead of silently leaving the guest pending.
537	      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
538	      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
539	    } else {
540	      var parts = [];
541	      if (sent) parts.push(sent + ' sent');
542	      if (cancelled) parts.push(cancelled + ' cancelled');
543	      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
544	    }
545	  } else {
546	    msg = 'Update failed (' + res.code + ').';
547	  }
548	  // Re-render so the card switches to Manage mode and shows fresh statuses.
549	  return CardService.newActionResponseBuilder()
550	    .setNotification(CardService.newNotification().setText(msg))
551	    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
552	    .build();
553	}
554	
555	function onPreview(e) {
556	  var iCalUid = e.parameters.iCalUid;
557	  patchFromForm_(iCalUid, e); // capture edits before previewing
558	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
559	  var inputs = formInputs_(e);
560	  var target = null;
561	  for (var i = 0; i < emails.length; i++) {
562	    if (formValue_(inputs['inc_' + emails[i]]) === 'on') { target = emails[i]; break; }
563	  }
564	  if (!target) return notify_('Turn on at least one guest to preview their email.');
565	
566	  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: target });
567	  if (pv.code !== 200 || !pv.json.previewToken) return notify_('Preview failed (' + pv.code + ').');
568	
569	  // Open the REAL branded HTML in a popup overlay (the card can't render HTML).
570	  var url = ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
571	  return CardService.newActionResponseBuilder()
572	    .setOpenLink(CardService.newOpenLink()
573	      .setUrl(url)
574	      .setOpenAs(CardService.OpenAs.OVERLAY)
575	      .setOnClose(CardService.OnClose.NOTHING))
576	    .build();
577	}
578	
579	// ── Helpers ───────────────────────────────────────────────
580	function patchFromForm_(iCalUid, e) {
581	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
582	  var inputs = formInputs_(e);
583	  var guests = emails.map(function (em) {
584	    return {
585	      email: em,
586	      include: formValue_(inputs['inc_' + em]) === 'on', // OFF switches are absent → false
587	      name: formValue_(inputs['name_' + em]),
588	      phone: formValue_(inputs['phone_' + em])
589	    };
590	  });
591	  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
592	}
593	
594	function formInputs_(e) {
595	  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
596	}
597	function formValue_(input) {
598	  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
599	    return input.stringInputs.value[0];
600	  }
601	  return '';
602	}
603	function Boolean_(x) { return !!x; }
604	
605	function textPreview_(json) {
606	  var t = json.text || json.html || '';
607	  t = t.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
608	  return t.length > 1200 ? t.substring(0, 1200) + '…' : t;
609	}
610	
611	function notify_(msg) {
612	  return CardService.newActionResponseBuilder()
613	    .setNotification(CardService.newNotification().setText(msg))
614	    .build();
615	}
616	
617	function errorCard_(msg) {
618	  return CardService.newCardBuilder()
619	    .setHeader(CardService.newCardHeader()
620	      .setTitle('Something went wrong')
621	      .setImageUrl(ADDON_ICON_URL))
622	    .addSection(CardService.newCardSection()
623	      .addWidget(CardService.newDecoratedText()
624	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.DESCRIPTION))
625	        .setText(msg)
626	        .setWrapText(true)))
627	    .build();
628	}
