/**
 * Auxilio Visitor — Google Calendar add-on (card-first).
 *
 * The whole host flow lives in this card; it calls office-ops-engine over HTTPS.
 * Engine contract: ../office-ops-engine/spec/2026-06-16_calendar_addon_register_endpoint.md
 *
 * Apps Script (GAS, V8) — flat global scope, no imports/modules.
 * First version: push with clasp, then refine in the Apps Script editor (it can run
 * and log there; it can't be run from the monorepo).
 */

// Engine base URL. Default = the local-tunnel domain (npm run backendtunnel).
// Must also be listed in appsscript.json → urlFetchWhitelist.
var ENGINE_BASE = 'https://unyearning-olympia-unclimactic.ngrok-free.dev';

// Appointy logo embedded as a base64 data URI (gradient original from appointy.svg).
// Source: appointy.svg (copied from visitor-web/public/, also in this repo).
// Used by setImageUrl() in all card headers.
var ADDON_ICON_URL = 'data:image/svg+xml;base64,REDACTED';

// Primary brand colour — used for filled buttons and accent text.
var BRAND_COLOR = '#92288E';

// ── Triggers ──────────────────────────────────────────────
function onCalendarEventOpen(e) { return [buildVisitorCard_(e)]; }
function onCalendarEventUpdate(e) { return [buildVisitorCard_(e)]; }

// Serves the branded icon SVG at ?asset=logo. ContentService.MimeType.XML is the
// closest available type to image/svg+xml in GAS. The manifest logoUrl below points
// to visitor-web instead, which nginx serves with the correct image/svg+xml header.
function doGet(e) {
  if (e && e.parameter && e.parameter.asset === 'logo') {
    var b64 = ADDON_ICON_URL.split(',')[1];
    var svgText = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
    return ContentService.createTextOutput(svgText).setMimeType(ContentService.MimeType.XML);
  }
  return ContentService.createTextOutput('Auxilio Workspace Add-on');
}

// Three-dot menu → Sign out.
// NOTE: we deliberately do NOT call ScriptApp.invalidateAuth() — invalidating auth
// breaks every subsequent add-on invocation (incl. re-clicking this very item) with
// "Unspecified error invoking the add-on", because the platform can't run any
// function once authorization is cleared. A Calendar add-on also has no login page
// we can navigate to (Google only shows the consent prompt automatically on the next
// authorized open). So sign-out routes the user to the real, linkable destination:
// the Google Account permissions page, where they can remove access / switch account.
// Removing access there forces full re-consent the next time they open the add-on.
function onSignOut(e) {
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Sign out')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
        .setText('Switch account or re-grant access')
        .setBottomLabel('Remove Auxilio Visitor from your Google account, then reopen the add-on — you\'ll be asked to sign in and grant access again.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Manage access')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setOpenLink(CardService.newOpenLink()
          .setUrl('https://myaccount.google.com/permissions'))))
    .build();
  return CardService.newUniversalActionResponseBuilder()
    .displayAddOnCards([card])
    .build();
}

function onHomepage(e) {
  var introSection = CardService.newCardSection()
    .addWidget(CardService.newTextParagraph()
      .setText('Open a calendar event with external guests to register visitor passes.'));

  var howSection = CardService.newCardSection()
    .setHeader('How it works')
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
      .setText('Choose who gets a pass')
      .setBottomLabel('Toggle guests on or off from the event\'s attendee list.')
      .setWrapText(true))
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
      .setText('Review and send')
      .setBottomLabel('Edit names and phone numbers, preview the invite email, then send.')
      .setWrapText(true))
    .addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.TICKET))
      .setText('Manage anytime')
      .setBottomLabel('Cancel or resend passes by toggling them off and on.')
      .setWrapText(true));

  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Auxilio Visitor')
      .setSubtitle('Visitor passes from your calendar')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(introSection)
    .addSection(howSection)
    .build();
}

// ── Engine HTTP ───────────────────────────────────────────
function engineFetch_(path, method, payload) {
  var options = {
    method: method,
    contentType: 'application/json',
    muteHttpExceptions: true,
    headers: {
      Authorization: 'Bearer ' + ScriptApp.getIdentityToken(),
      'ngrok-skip-browser-warning': 'true'
    }
  };
  if (payload) options.payload = JSON.stringify(payload);
  var res = UrlFetchApp.fetch(ENGINE_BASE + path, options);
  var json = {};
  try { json = JSON.parse(res.getContentText()); } catch (err) {}
  return { code: res.getResponseCode(), json: json };
}

// Resolve attendees + (best-effort) iCalUID/title/times for the open event.
// Attendees come from the add-on payload (currentEventAccess) — no API call needed.
// The Calendar API lookup enriches with the canonical iCalUID + title/times so the
// engine dedups with the .ics/OAuth paths; if it fails we fall back to the event id
// as the key so the flow still works.
function loadEvent_(e) {
  var cal = e.calendar || {};
  var calendarId = cal.calendarId;
  var eventId = cal.id;
  var payloadAtt = cal.attendees || [];
  var info = {
    iCalUid: eventId,
    providerEventId: eventId,
    keySource: 'eventId',
    title: '',
    start: null,
    end: null,
    attendees: mapAttendees_(payloadAtt),
    debug: ''
  };
  var ev = fetchEventWithRetry_(calendarId, eventId);
  if (ev) {
    if (ev.iCalUID) { info.iCalUid = ev.iCalUID; info.keySource = 'iCalUID'; }
    info.title = ev.summary || '';
    info.start = ev.start ? (ev.start.dateTime || ev.start.date) : null;
    info.end = ev.end ? (ev.end.dateTime || ev.end.date) : null;
    var apiAtt = mapAttendees_(ev.attendees);
    if (info.attendees.length === 0 && apiAtt.length > 0) info.attendees = apiAtt;
  }
  info.debug = 'key=' + info.keySource + ' guests=' + info.attendees.length;
  return info;
}

// Resolve the event from the Calendar API, tolerating transient 404s: retry once
// after a short wait (eventual consistency) and try the primary calendar as a
// fallback for the calendarId. Returns the event resource or null.
function fetchEventWithRetry_(calendarId, eventId) {
  var targets = [];
  if (calendarId) targets.push(calendarId);
  if (calendarId !== 'primary') targets.push('primary');
  for (var attempt = 0; attempt < 2; attempt++) {
    for (var t = 0; t < targets.length; t++) {
      try {
        var ev = Calendar.Events.get(targets[t], eventId);
        if (ev) return ev;
      } catch (err) {
        // 404 / transient → fall through to the next target / retry.
      }
    }
    if (attempt === 0) Utilities.sleep(500);
  }
  return null;
}

// Per-guest avatar: Gravatar keyed on the email (real photo if they have one),
// falling back to a coloured initials avatar (ui-avatars) when they don't. Rendered
// as a circular image icon. Image URLs are fetched by Google's client, so they
// don't need urlFetchWhitelist.
function avatarIcon_(email, name) {
  var initials = (name || email || '?').trim().charAt(0).toUpperCase() || '?';
  var fallback = 'https://ui-avatars.com/api/?name=' + encodeURIComponent(initials) +
    '&size=64&background=92288E&color=ffffff&bold=true';
  var url = 'https://www.gravatar.com/avatar/' + md5Hex_((email || '').trim().toLowerCase()) +
    '?s=64&d=' + encodeURIComponent(fallback);
  return CardService.newIconImage()
    .setIconUrl(url)
    .setImageCropType(CardService.ImageCropType.CIRCLE);
}

// Minimal MD5 → lowercase hex (Gravatar needs MD5 of the email).
function md5Hex_(str) {
  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, str, Utilities.Charset.UTF_8);
  var hex = '';
  for (var i = 0; i < bytes.length; i++) {
    var b = (bytes[i] + 256) % 256;
    hex += (b < 16 ? '0' : '') + b.toString(16);
  }
  return hex;
}

function mapAttendees_(list) {
  return (list || [])
    .filter(function (a) { return a && a.email && !a.self && !a.organizer && !a.resource; })
    .map(function (a) {
      // Google often sets displayName = the email for non-contacts → treat as no name.
      var nm = (a.displayName && a.displayName !== a.email) ? a.displayName : '';
      return { email: a.email, name: nm };
    });
}

// ── Card helpers ──────────────────────────────────────────

function statusLabel_(g) {
  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled — toggle on to resend</font>';
  return g.include === false
    ? '<font color="#9aa0a6">No pass</font>'
    : '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
}

// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
function buildStatLine_(roster) {
  var total = roster.length;
  var sent = 0, pending = 0, cancelled = 0;
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    if (g.status === 'sent') sent++;
    else if (g.status === 'cancelled') cancelled++;
    else if (g.include !== false) pending++;
  }
  var parts = [total + (total === 1 ? ' guest' : ' guests')];
  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
  return parts.join('  ·  ');
}

// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
function formatEventSubtitle_(ev) {
  if (!ev.start) return ev.title || '';
  try {
    var d = new Date(ev.start);
    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
    var datePart = day + ', ' + time;
    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
  } catch (err) {
    return ev.title || '';
  }
}

// ── Main card ─────────────────────────────────────────────
function buildVisitorCard_(e) {
  // Fast path: no external guests in the payload → render immediately without any
  // network call. Keeps empty events snappy so the loader never lingers.
  var cal = e.calendar || {};
  if (mapAttendees_(cal.attendees).length === 0) {
    return CardService.newCardBuilder()
      .setHeader(CardService.newCardHeader()
        .setTitle('Visitor passes')
        .setImageUrl(ADDON_ICON_URL))
      .addSection(CardService.newCardSection()
        .addWidget(CardService.newDecoratedText()
          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
          .setText('No guests yet')
          .setBottomLabel('Add a guest to this event.')
          .setWrapText(true)))
      .build();
  }

  var ev = loadEvent_(e);
  if (!ev.iCalUid) return errorCard_('No event id in payload (' + ev.debug + ') — save the event, then reopen.');

  var organizerEmail = (cal.organizer && cal.organizer.email) || '';
  var res = engineFetch_('/api/visitor/calendar/addon/draft', 'POST', {
    iCalUid: ev.iCalUid, providerEventId: ev.providerEventId, organizerEmail: organizerEmail,
    title: ev.title, start: ev.start, end: ev.end, attendees: ev.attendees
  });
  if (res.code === 401) return errorCard_('Not authorized. Check the engine\'s AUXILIO_WORKSPACE_OAUTH_CLIENT_ID.');
  if (res.code === 403) return errorCard_('Your domain is not allowed to host visits.');
  if (res.code !== 200) return errorCard_('Engine error ' + res.code + '. Try refreshing the page.');

  var draft = res.json;
  var roster = draft.roster || [];
  resolveAndStoreNames_(ev.iCalUid, roster);
  var managed = !!draft.materialized;

  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle(managed ? 'Manage passes' : 'Visitor passes')
      .setSubtitle(formatEventSubtitle_(ev))
      .setImageUrl(ADDON_ICON_URL));

  if (roster.length === 0) {
    return card
      .addSection(CardService.newCardSection()
        .addWidget(CardService.newDecoratedText()
          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
          .setText('No guests yet')
          .setBottomLabel('Add a guest to this event.')
          .setWrapText(true)))
      .build();
  }

  // Stat summary at the top (non-collapsible)
  card.addSection(CardService.newCardSection()
    .addWidget(CardService.newTextParagraph().setText(buildStatLine_(roster))));

  // One collapsible section per guest. The toggle row is always visible;
  // name + phone inputs collapse under it to keep long rosters scannable.
  var emails = [];
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    emails.push(g.email);

    var mainText   = g.name || g.email;
    var bottomText = g.name
      ? (g.email + '  ·  ' + statusLabel_(g))
      : statusLabel_(g);

    var sw = CardService.newSwitch()
      .setFieldName('inc_' + g.email)
      .setValue('on')
      .setSelected(g.include !== false);

    var guestSection = CardService.newCardSection()
      .setCollapsible(true)
      .setNumUncollapsibleWidgets(1)
      // ── Toggle row — always visible ──────────────────
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(avatarIcon_(g.email, g.name))
        .setText(mainText)
        .setBottomLabel(bottomText)
        .setWrapText(true)
        .setSwitchControl(sw))
      // ── Name input — collapses ───────────────────────
      .addWidget(CardService.newTextInput()
        .setFieldName('name_' + g.email)
        .setTitle('Full name')
        .setValue(g.name || ''))
      // ── Phone label with icon — collapses ───────────
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PHONE))
        .setText('Phone number')
        .setWrapText(true))
      // ── Phone input — collapses ──────────────────────
      .addWidget(CardService.newTextInput()
        .setFieldName('phone_' + g.email)
        .setTitle('Phone')
        .setValue(g.phone || ''));

    card.addSection(guestSection);
  }

  var params = { iCalUid: ev.iCalUid, emails: emails.join(',') };
  addCalendarSyncSection_(card, draft.calendarSync);

  // Primary CTA pinned to the footer — always reachable without scrolling.
  card.setFixedFooter(CardService.newFixedFooter()
    .setPrimaryButton(CardService.newTextButton()
      .setText(managed ? 'Update passes' : 'Send passes')
      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
      .setBackgroundColor(BRAND_COLOR)
      .setOnClickAction(CardService.newAction()
        .setFunctionName('onReviewSend')
        .setParameters(params)))
    .setSecondaryButton(CardService.newTextButton()
      .setText('Preview email')
      .setOnClickAction(CardService.newAction()
        .setFunctionName('onPreview')
        .setParameters(params))));

  return card.build();
}

// Background auto-sync (move/delete) status. Only rendered when the host owns the event.
function addCalendarSyncSection_(card, sync) {
  if (!sync || !sync.relevant) return;
  var section = CardService.newCardSection();
  if (sync.connected) {
    section.addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.STAR))
      .setText('Auto-sync is on')
      .setBottomLabel('Move or cancel this meeting and passes update automatically.')
      .setWrapText(true));
  } else if (sync.connectUrl) {
    section
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.CLOCK))
        .setText('Keep passes in sync')
        .setBottomLabel('Connect your calendar so moving or cancelling this meeting updates passes automatically — even when this panel is closed.')
        .setWrapText(true))
      .addWidget(CardService.newTextButton()
        .setText('Connect calendar')
        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
        .setBackgroundColor(BRAND_COLOR)
        .setOpenLink(CardService.newOpenLink()
          .setUrl(sync.connectUrl)
          .setOpenAs(CardService.OpenAs.OVERLAY)));
  }
  card.addSection(section);
}

// ── Actions ───────────────────────────────────────────────
// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
function cardDeriveName_(email) {
  var local = (email.split('@')[0] || email);
  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
}

var _peopleWarmed = false;
function peopleSearch_(path, email) {
  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
  var base = 'https://people.googleapis.com/v1/';
  // searchContacts/otherContacts.search require a warmup (empty-query) call first.
  if (!_peopleWarmed) {
    UrlFetchApp.fetch(base + 'people:searchContacts?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
    UrlFetchApp.fetch(base + 'otherContacts:search?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
    _peopleWarmed = true;
    Utilities.sleep(200);
  }
  var url = base + path + '?query=' + encodeURIComponent(email) + '&readMask=names,emailAddresses';
  var resp = UrlFetchApp.fetch(url, { headers: headers, muteHttpExceptions: true });
  if (resp.getResponseCode() !== 200) return '';
  var results = (JSON.parse(resp.getContentText()).results) || [];
  for (var i = 0; i < results.length; i++) {
    var person = results[i].person || {};
    var emails = person.emailAddresses || [];
    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
    if (match && person.names && person.names.length) return person.names[0].displayName || '';
  }
  return '';
}

function resolveContactName_(email) {
  try {
    return peopleSearch_('people:searchContacts', email) || peopleSearch_('otherContacts:search', email);
  } catch (err) {
    return '';
  }
}

// For each guest whose name is still auto-derived, look up the real contact name
// and PATCH it onto the draft (so subsequent opens skip the lookup). Mutates roster.
function resolveAndStoreNames_(iCalUid, roster) {
  var patches = [];
  for (var i = 0; i < roster.length; i++) {
    var g = roster[i];
    var looksDerived = !g.name || g.name === cardDeriveName_(g.email);
    if (!looksDerived) continue;
    var resolved = resolveContactName_(g.email);
    if (resolved && resolved !== g.name) {
      g.name = resolved;                       // reflect immediately in this render
      patches.push({ email: g.email, name: resolved });
    }
  }
  if (patches.length) {
    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
  }
}

// Review step: persist edits, then push a textual confirm card. Cards can't
// render HTML inline (that's the "Preview email" overlay link), so the review
// here is the recipient list + what will happen — the guard before sending.
function onReviewSend(e) {
  var iCalUid = e.parameters.iCalUid;
  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  var included = [];
  var excluded = [];
  for (var i = 0; i < emails.length; i++) {
    var em = emails[i];
    var on = formValue_(inputs['inc_' + em]) === 'on';
    var name = formValue_(inputs['name_' + em]) || em;
    (on ? included : excluded).push({ email: em, name: name });
  }
  if (!included.length) return notify_('Turn on at least one guest before sending.');
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
    .build();
}

function buildConfirmCard_(params, included, excluded) {
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Send ' + included.length + ' pass' + (included.length > 1 ? 'es' : '') + '?')
      .setImageUrl(ADDON_ICON_URL));
  var sec = CardService.newCardSection().setHeader('These guests get a pass');
  for (var i = 0; i < included.length; i++) {
    sec.addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
      .setText(included[i].name)
      .setBottomLabel(included[i].email)
      .setWrapText(true));
  }
  card.addSection(sec);
  if (excluded.length) {
    var ex = CardService.newCardSection().setHeader('Skipped (no pass / cancelled if sent before)');
    for (var j = 0; j < excluded.length; j++) {
      ex.addWidget(CardService.newDecoratedText()
        .setText(excluded[j].name).setBottomLabel(excluded[j].email).setWrapText(true));
    }
    card.addSection(ex);
  }
  card.setFixedFooter(CardService.newFixedFooter()
    .setPrimaryButton(CardService.newTextButton()
      .setText('Send passes')
      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
      .setBackgroundColor(BRAND_COLOR)
      .setOnClickAction(CardService.newAction().setFunctionName('onSaveAndSend').setParameters(params)))
    .setSecondaryButton(CardService.newTextButton()
      .setText('Back')
      .setOnClickAction(CardService.newAction().setFunctionName('onConfirmBack').setParameters(params))));
  return card.build();
}

function onConfirmBack(e) {
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().popCard())
    .build();
}

function onSaveAndSend(e) {
  var iCalUid = e.parameters.iCalUid;
  patchFromForm_(iCalUid, e);                       // persist toggles/name/phone first
  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', { iCalUid: iCalUid });
  var msg;
  if (res.code === 200) {
    var sent = (res.json.created || []).length;
    var cancelled = (res.json.cancelled || []).length;
    var failed = res.json.failed || [];
    if (failed.length) {
      // Surface WHY a pass couldn't be sent (most often: event time in the past)
      // instead of silently leaving the guest pending.
      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
    } else {
      var parts = [];
      if (sent) parts.push(sent + ' sent');
      if (cancelled) parts.push(cancelled + ' cancelled');
      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
    }
  } else {
    msg = 'Update failed (' + res.code + ').';
  }
  // Re-render so the card switches to Manage mode and shows fresh statuses.
  return CardService.newActionResponseBuilder()
    .setNotification(CardService.newNotification().setText(msg))
    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
    .build();
}

function onPreview(e) {
  var iCalUid = e.parameters.iCalUid;
  patchFromForm_(iCalUid, e); // capture edits before previewing
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  var target = null;
  for (var i = 0; i < emails.length; i++) {
    if (formValue_(inputs['inc_' + emails[i]]) === 'on') { target = emails[i]; break; }
  }
  if (!target) return notify_('Turn on at least one guest to preview their email.');

  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: target });
  if (pv.code !== 200 || !pv.json.previewToken) return notify_('Preview failed (' + pv.code + ').');

  // Open the REAL branded HTML in a popup overlay (the card can't render HTML).
  var url = ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
  return CardService.newActionResponseBuilder()
    .setOpenLink(CardService.newOpenLink()
      .setUrl(url)
      .setOpenAs(CardService.OpenAs.OVERLAY)
      .setOnClose(CardService.OnClose.NOTHING))
    .build();
}

// ── Helpers ───────────────────────────────────────────────
function patchFromForm_(iCalUid, e) {
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  var guests = emails.map(function (em) {
    return {
      email: em,
      include: formValue_(inputs['inc_' + em]) === 'on', // OFF switches are absent → false
      name: formValue_(inputs['name_' + em]),
      phone: formValue_(inputs['phone_' + em])
    };
  });
  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
}

function formInputs_(e) {
  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
}
function formValue_(input) {
  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
    return input.stringInputs.value[0];
  }
  return '';
}
function Boolean_(x) { return !!x; }

function textPreview_(json) {
  var t = json.text || json.html || '';
  t = t.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
  return t.length > 1200 ? t.substring(0, 1200) + '…' : t;
}

function notify_(msg) {
  return CardService.newActionResponseBuilder()
    .setNotification(CardService.newNotification().setText(msg))
    .build();
}

function errorCard_(msg) {
  return CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Something went wrong')
      .setImageUrl(ADDON_ICON_URL))
    .addSection(CardService.newCardSection()
      .addWidget(CardService.newDecoratedText()
        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.DESCRIPTION))
        .setText(msg)
        .setWrapText(true)))
    .build();
}

