1	/**
2	 * Visit Draft store — the curated visitor-invite roster for the Auxilio Workspace
3	 * calendar add-on.
4	 *
5	 * The add-on builds/loads a draft per event (keyed by iCalUID), the host edits it
6	 * in the card, and on send we materialize invites from the INCLUDED guests via the
7	 * shared `createVisitorInvite` (same call every other channel uses — no logic fork).
8	 *
9	 * Once materialized, `calendar_event_links.draft_authoritative=1` (written by the
10	 * caller, not here) makes this the source of truth: passive producers (.ics / OAuth
11	 * poll) then only retime/cancel — they re-issue from this roster, never raw attendees.
12	 *
13	 * Spec: spec/2026-06-16_calendar_addon_register_endpoint.md §4.
14	 * NOTE: this module must NOT import calendar-ingest (calendar-ingest imports this).
15	 */
16	
17	import { getDb } from '../../lib/database';
18	import { createVisitorInvite, notifyInviteCancelled, RESCHEDULED_EMAIL_OVERRIDE } from './invite-manager';
19	import { cancelInvitationById, findActiveInvitationForVisitor, getActiveInvitationById } from './db';
20	import { isInvitationLinkedToOtherEvent, rekeyCalendarLink, isVisitorAttendee } from './calendar-ingest';
21	import { resolveHostContactByEmail } from './host-resolution';
22	
23	const DEFAULT_TENANT_ID = 'appointy';
24	
25	export type DraftGuestStatus = 'pending' | 'sending' | 'sent' | 'cancelled';
26	
27	export interface DraftGuest {
28	  email: string;
29	  name: string;
30	  phone?: string;
31	  /** Host's include/exclude toggle — the online/offline solution. */
32	  include: boolean;
33	  passTemplateKey?: string;
34	  emailTemplateKey?: string;
35	  status: DraftGuestStatus;
36	  /** Set once an invite has been created for this guest. */
37	  invitationId?: string;
38	}
39	
40	export interface VisitDraft {
41	  iCalUid: string;
42	  tenantId: string;
43	  providerEventId?: string;
44	  title?: string;
45	  hostEmail?: string;
46	  location?: string;
47	  roster: DraftGuest[];
48	  eventStart?: string;
49	  eventEnd?: string;
50	  materialized: boolean;
51	}
52	
53	export interface BuildDraftInput {
54	  iCalUid: string;
55	  tenantId?: string;
56	  providerEventId?: string;
57	  title?: string;
58	  hostEmail?: string;
59	  attendees: { email: string; name?: string }[];
60	  eventStart?: string;
61	  eventEnd?: string;
62	  location?: string;
63	}
64	
65	export interface DraftPatch {
66	  location?: string;
67	  guests?: {
68	    email: string;
69	    include?: boolean;
70	    name?: string;
71	    phone?: string;
72	    passTemplateKey?: string;
73	    emailTemplateKey?: string;
74	  }[];
75	}
76	
77	export interface PassResult {
78	  visitorEmail: string;
79	  visitorName: string;
80	  invitationId: string;
81	  passUrl: string;
82	  status: 'sent';
83	}
84	
85	// ─── IST helpers (mirror calendar-ingest; createVisitorInvite expects IST date/time) ──
86	
87	const IST_DATE = new Intl.DateTimeFormat('en-CA', {
88	  timeZone: 'Asia/Kolkata',
89	  year: 'numeric',
90	  month: '2-digit',
91	  day: '2-digit',
92	});
93	const IST_TIME = new Intl.DateTimeFormat('en-GB', {
94	  timeZone: 'Asia/Kolkata',
95	  hour: '2-digit',
96	  minute: '2-digit',
97	  hour12: false,
98	});
99	const istDate = (d: Date): string => IST_DATE.format(d);
100	const istTime = (d: Date): string => IST_TIME.format(d);
101	
102	function nameFromEmail(email: string): string {
103	  const local = email.split('@')[0] ?? email;
104	  return (
105	    local
106	      .replace(/[._-]+/g, ' ')
107	      .replace(/\b\w/g, (c) => c.toUpperCase())
108	      .trim() || email
109	  );
110	}
111	
112	// ─── Row mapping ──────────────────────────────────────────────
113	
114	interface DraftRow {
115	  ical_uid: string;
116	  tenant_id: string | null;
117	  provider_event_id: string | null;
118	  title: string | null;
119	  host_email: string | null;
120	  location: string | null;
121	  roster: string | null;
122	  event_start: string | null;
123	  event_end: string | null;
124	  materialized: number | null;
125	}
126	
127	function rowToDraft(row: DraftRow): VisitDraft {
128	  let roster: DraftGuest[] = [];
129	  try {
130	    const parsed = JSON.parse(row.roster ?? '[]');
131	    if (Array.isArray(parsed)) roster = parsed as DraftGuest[];
132	  } catch {
133	    /* corrupt JSON → empty roster */
134	  }
135	  return {
136	    iCalUid: row.ical_uid,
137	    tenantId: row.tenant_id ?? DEFAULT_TENANT_ID,
138	    providerEventId: row.provider_event_id ?? undefined,
139	    title: row.title ?? undefined,
140	    hostEmail: row.host_email ?? undefined,
141	    location: row.location ?? undefined,
142	    roster,
143	    eventStart: row.event_start ?? undefined,
144	    eventEnd: row.event_end ?? undefined,
145	    materialized: !!row.materialized,
146	  };
147	}
148	
149	// ─── Persistence ──────────────────────────────────────────────
150	
151	export async function getDraft(iCalUid: string): Promise<VisitDraft | null> {
152	  const db = await getDb();
153	  const result = await db.execute({
154	    sql: `SELECT * FROM visit_drafts WHERE ical_uid = ? LIMIT 1`,
155	    args: [iCalUid],
156	  });
157	  const row = result.rows[0] as unknown as DraftRow | undefined;
158	  return row ? rowToDraft(row) : null;
159	}
160	
161	/**
162	 * Fallback lookup by Google's stable event id. `Events.get` is flaky, so the same
163	 * event can be keyed on the real iCalUID one open and on the eventId fallback the
164	 * next — `provider_event_id` (the Google event.id) is stable across both, so this
165	 * recovers the existing draft and prevents key-drift from rebuilding it fresh
166	 * (which would wipe the host's toggle/edit state).
167	 */
168	export async function getDraftByProviderEventId(providerEventId: string): Promise<VisitDraft | null> {
169	  if (!providerEventId) return null;
170	  const db = await getDb();
171	  const result = await db.execute({
172	    sql: `SELECT * FROM visit_drafts WHERE provider_event_id = ? LIMIT 1`,
173	    args: [providerEventId],
174	  });
175	  const row = result.rows[0] as unknown as DraftRow | undefined;
176	  return row ? rowToDraft(row) : null;
177	}
178	
179	/** Re-key a draft to a newly-resolved iCalUID (Events.get recovered after a fallback). */
180	export async function rekeyDraft(oldICalUid: string, newICalUid: string): Promise<void> {
181	  if (!oldICalUid || !newICalUid || oldICalUid === newICalUid) return;
182	  const db = await getDb();
183	  // Delete any empty placeholder under the new key first, then move the row.
184	  await db.execute({ sql: `DELETE FROM visit_drafts WHERE ical_uid = ?`, args: [newICalUid] });
185	  await db.execute({
186	    sql: `UPDATE visit_drafts SET ical_uid = ?, updated_at = now()::text WHERE ical_uid = ?`,
187	    args: [newICalUid, oldICalUid],
188	  });
189	}
190	
191	export async function upsertDraft(draft: VisitDraft): Promise<void> {
192	  const db = await getDb();
193	  await db.execute({
194	    sql: `INSERT INTO visit_drafts (ical_uid, tenant_id, provider_event_id, title, host_email, location, roster, event_start, event_end, materialized, updated_at)
195	          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, now()::text)
196	          ON CONFLICT (ical_uid) DO UPDATE SET
197	            tenant_id = EXCLUDED.tenant_id,
198	            provider_event_id = COALESCE(EXCLUDED.provider_event_id, visit_drafts.provider_event_id),
199	            title = EXCLUDED.title,
200	            host_email = EXCLUDED.host_email,
201	            location = EXCLUDED.location,
202	            roster = EXCLUDED.roster,
203	            event_start = EXCLUDED.event_start,
204	            event_end = EXCLUDED.event_end,
205	            materialized = EXCLUDED.materialized,
206	            updated_at = now()::text`,
207	    args: [
208	      draft.iCalUid,
209	      draft.tenantId,
210	      draft.providerEventId ?? null,
211	      draft.title ?? null,
212	      draft.hostEmail ?? null,
213	      draft.location ?? null,
214	      JSON.stringify(draft.roster),
215	      draft.eventStart ?? null,
216	      draft.eventEnd ?? null,
217	      draft.materialized ? 1 : 0,
218	    ],
219	  });
220	}
221	
222	// ─── Build / load ─────────────────────────────────────────────
223	
224	/** Most recent phone we've seen for this email — pre-fill from visitor history. */
225	async function lastKnownPhoneFor(email: string): Promise<string | undefined> {
226	  const db = await getDb();
227	  const result = await db.execute({
228	    sql: `SELECT visitor_phone FROM visitor_invitations
229	          WHERE lower(visitor_email) = ? AND visitor_phone IS NOT NULL AND visitor_phone <> ''
230	          ORDER BY created_at DESC LIMIT 1`,
231	    args: [email.toLowerCase()],
232	  });
233	  const row = result.rows[0] as unknown as { visitor_phone?: string } | undefined;
234	  return row?.visitor_phone || undefined;
235	}
236	
237	export type PhoneLookup = (email: string) => Promise<string | undefined>;
238	/** Decides each guest's DEFAULT toggle. Defaults to "everyone on" when omitted. */
239	export type IncludeDecider = (email: string) => boolean;
240	
241	/**
242	 * Build the curated roster from raw attendees: drop the host + blanks, dedup
243	 * case-insensitively, derive a name when absent, pre-fill phone via `phoneLookup`,
244	 * and set each guest's DEFAULT toggle via `includeDecider` (so same-workspace /
245	 * same-location colleagues come pre-toggled-OFF — same rule as every other channel).
246	 * Pure (DB + classification injected) → unit-testable.
247	 */
248	export async function buildRoster(
249	  attendees: { email: string; name?: string }[],
250	  hostEmail: string | undefined,
251	  phoneLookup: PhoneLookup,
252	  includeDecider: IncludeDecider = () => true,
253	): Promise<DraftGuest[]> {
254	  const host = hostEmail?.toLowerCase();
255	  const seen = new Set<string>();
256	  const roster: DraftGuest[] = [];
257	  for (const attendee of attendees) {
258	    const email = attendee.email?.toLowerCase();
259	    if (!email || email === host || seen.has(email)) continue;
260	    seen.add(email);
261	    roster.push({
262	      email,
263	      name: attendee.name?.trim() || nameFromEmail(email),
264	      phone: await phoneLookup(email),
265	      include: includeDecider(email),
266	      status: 'pending',
267	    });
268	  }
269	  return roster;
270	}
271	
272	/**
273	 * Adopt passes that already exist for these guests (created via ANY channel —
274	 * dashboard, Slack, Excel, or a prior add-on send) so the add-on never offers a
275	 * DUPLICATE. Mutates each guest in place: sets status='sent' + invitationId when an
276	 * active pass is found. Two matchers, cheapest first:
277	 *   1. Exact: our host-invite .ics uses UID `<invitationId>@appointy-visitor`; if
278	 *      Google preserved that UID, resolve the invitation id directly.
279	 *   2. Identity: an active invitation for the same visitor_email on the event's date.
280	 * Returns true if any guest was adopted (→ caller marks the draft materialized).
281	 */
282	async function adoptExistingPasses(roster: DraftGuest[], iCalUid: string, eventDate: string): Promise<boolean> {
283	  // (1) Exact UID match — only when the event key looks like our own ICS UID.
284	  const uidMatch = /^(.+)@appointy-visitor$/.exec(iCalUid ?? '');
285	  const exactInviteId = uidMatch?.[1];
286	  let adopted = false;
287	
288	  for (const guest of roster) {
289	    if (guest.status === 'sent' && guest.invitationId) continue; // already linked
290	    let existing = exactInviteId ? await getActiveInvitationById(exactInviteId).catch(() => null) : null;
291	    // Exact match must actually be THIS guest's pass (UID identifies the visit, but
292	    // an event could have several guests — fall back to identity if it isn't them).
293	    if (existing && existing.visitor_email?.toLowerCase() !== guest.email.toLowerCase()) existing = null;
294	    if (!existing && eventDate) {
295	      const candidate = await findActiveInvitationForVisitor(guest.email, eventDate).catch(() => null);
296	      // Only adopt by identity if the pass isn't already owned by ANOTHER event —
297	      // otherwise a new event would wrongly inherit a different meeting's pass.
298	      if (candidate && !(await isInvitationLinkedToOtherEvent(candidate.id, iCalUid).catch(() => false))) {
299	        existing = candidate;
300	      }
301	    }
302	    if (existing) {
303	      guest.invitationId = existing.id;
304	      guest.status = 'sent';
305	      // A guest who already has a pass IS included, regardless of the classifier's
306	      // default-off (e.g. a same-location colleague the host deliberately invited).
307	      // Otherwise a later "Update" would cancel their adopted pass.
308	      guest.include = true;
309	      if (!guest.name || guest.name.toLowerCase() === guest.email.toLowerCase()) {
310	        guest.name = existing.visitor_name || guest.name;
311	      }
312	      if (!guest.phone && existing.visitor_phone) guest.phone = existing.visitor_phone;
313	      adopted = true;
314	    }
315	  }
316	  return adopted;
317	}
318	
319	/** IST date (YYYY-MM-DD) for an event start, to match invitations.expected_date. */
320	function eventDateIST(eventStart?: string): string {
321	  return eventStart ? istDate(new Date(eventStart)) : istDate(new Date());
322	}
323	
324	/**
325	 * A pass duration ALWAYS equals the calendar event's start/end (decision
326	 * 2026-06-17). Returns valid dates, or null when the event times are missing —
327	 * callers must then NOT guess (no "now/+1h" fallback), and surface a failure
328	 * instead. Allows date-only (all-day) values.
329	 */
330	function resolveEventWindow(draft: VisitDraft): { start: Date; end: Date } | null {
331	  if (!draft.eventStart || !draft.eventEnd) return null;
332	  const start = new Date(draft.eventStart);
333	  const end = new Date(draft.eventEnd);
334	  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
335	  return { start, end };
336	}
337	
338	const EVENT_TIME_MISSING = 'Could not read the event time — reopen the event and try again.';
339	
340	async function buildDraft(input: BuildDraftInput): Promise<VisitDraft> {
341	  // Default each guest's toggle by the SAME rule as every other channel: external
342	  // or different-office → ON; same-workspace same/no-location → OFF (host can still
343	  // toggle on). isVisitorAttendee resolves the host's office internally.
344	  const includeDecider: IncludeDecider = (email) => isVisitorAttendee(email, input.hostEmail);
345	
346	  const roster = await buildRoster(input.attendees, input.hostEmail, lastKnownPhoneFor, includeDecider);
347	  const adopted = await adoptExistingPasses(roster, input.iCalUid, eventDateIST(input.eventStart));
348	  return {
349	    iCalUid: input.iCalUid,
350	    tenantId: input.tenantId ?? DEFAULT_TENANT_ID,
351	    providerEventId: input.providerEventId,
352	    title: input.title,
353	    hostEmail: input.hostEmail?.toLowerCase(),
354	    location: input.location,
355	    roster,
356	    eventStart: input.eventStart,
357	    eventEnd: input.eventEnd,
358	    // If a pass already exists for any guest, open straight into Manage mode.
359	    materialized: adopted,
360	  };
361	}
362	
363	export interface GetOrCreateOpts {
364	  /**
365	   * When true (the trusted card-open path), guests removed from the event are
366	   * dropped from the roster and any sent pass is cancelled. When false (the
367	   * OAuth poll — which can deliver partial attendee lists), removals are NOT
368	   * acted on: existing guests are kept as-is. Decision 2026-06-17 (plan §8B).
369	   */
370	  reconcileRemovals?: boolean;
371	}
372	
373	/**
374	 * Load-or-build the draft for an event, keeping it in sync with the current
375	 * attendee list.
376	 * - No draft → build + persist from the incoming attendees.
377	 * - Existing draft → add newly-invited attendees (as pending/included), preserve
378	 *   the host's edits (include toggle, name, phone, status, invitationId) for
379	 *   guests already present, and reconcile removals per `reconcileRemovals`.
380	 */
381	export async function getOrCreateDraft(
382	  input: BuildDraftInput,
383	  opts: GetOrCreateOpts = {},
384	): Promise<VisitDraft> {
385	  const built = await buildDraft(input);
386	  let existing = await getDraft(input.iCalUid);
387	
388	  // Key-drift recovery: if not found by iCalUid but we have the stable Google
389	  // event id, find the draft under its old key and re-key it to the now-known
390	  // iCalUid. Prevents a flaky Events.get from rebuilding a fresh draft (which would
391	  // wipe the host's toggle/edit state).
392	  if (!existing && input.providerEventId) {
393	    const byProvider = await getDraftByProviderEventId(input.providerEventId);
394	    if (byProvider && byProvider.iCalUid !== input.iCalUid) {
395	      // Move BOTH the draft and its ledger row onto the now-resolved iCalUid so
396	      // every later lookup (send, poll reschedule, cancel) stays consistent.
397	      await rekeyDraft(byProvider.iCalUid, input.iCalUid);
398	      await rekeyCalendarLink(byProvider.iCalUid, input.iCalUid).catch((e) => console.warn('[VisitDraft] link rekey failed:', e));
399	      existing = await getDraft(input.iCalUid);
400	    } else if (byProvider) {
401	      existing = byProvider;
402	    }
403	  }
404	
405	  if (!existing) {
406	    await upsertDraft(built);
407	    return built;
408	  }
409	
410	  const prevByEmail: Record<string, DraftGuest> = {};
411	  for (const g of existing.roster) prevByEmail[g.email.toLowerCase()] = g;
412	  const incoming = new Set(built.roster.map((g) => g.email.toLowerCase()));
413	
414	  // Safety: an EMPTY incoming list means "unknown" (a transient/partial payload),
415	  // not "every guest was removed" — never mass-cancel on it. Only reconcile
416	  // removals when we actually received attendees.
417	  const reconcileRemovals = !!opts.reconcileRemovals && built.roster.length > 0;
418	
419	  // 1) Current attendees first (new ones added; existing ones keep their edits).
420	  const roster: DraftGuest[] = built.roster.map((g) => {
421	    const prev = prevByEmail[g.email.toLowerCase()];
422	    if (!prev) return g;
423	    const name = prev.name && prev.name.toLowerCase() !== prev.email.toLowerCase() ? prev.name : g.name;
424	    return { ...prev, name };
425	  });
426	
427	  // 2) Guests in the draft but no longer on the event.
428	  for (const prev of existing.roster) {
429	    if (incoming.has(prev.email.toLowerCase())) continue;
430	    if (reconcileRemovals) {
431	      // Trusted card path: cancel a sent pass, then drop the guest from the list.
432	      if (prev.status === 'sent' && prev.invitationId) {
433	        console.log(`[VisitDraft] guest ${prev.email} removed from event → cancelling pass ${prev.invitationId}`);
434	        const ok = await cancelInvitationById(prev.invitationId).catch((e) => {
435	          console.warn(`[VisitDraft] cancel-on-remove ${prev.invitationId} failed:`, e);
436	          return false;
437	        });
438	        if (ok) await notifyInviteCancelled(prev.invitationId, { reason: 'You were removed from the calendar event.' });
439	      } else {
440	        console.log(`[VisitDraft] guest ${prev.email} removed from event (no active pass to cancel)`);
441	      }
442	      // dropped (not pushed)
443	    } else {
444	      // Conservative poll path: keep the guest untouched.
445	      roster.push(prev);
446	    }
447	  }
448	
449	  const refreshed: VisitDraft = {
450	    ...existing,
451	    title: input.title ?? existing.title,
452	    location: existing.location ?? input.location,
453	    eventStart: input.eventStart ?? existing.eventStart,
454	    eventEnd: input.eventEnd ?? existing.eventEnd,
455	    providerEventId: input.providerEventId ?? existing.providerEventId,
456	    roster,
457	    materialized: existing.materialized || roster.some((g) => g.status === 'sent'),
458	  };
459	  await upsertDraft(refreshed);
460	  return refreshed;
461	}
462	
463	/**
464	 * Resolve a host's display name from the Workspace-linked staff registry by email.
465	 * The add-on's ID token carries no usable name claim (no profile scope), so we
466	 * never trust the email-derived fallback when a real staff name exists.
467	 */
468	export async function resolveHostDisplayName(email: string | undefined, fallback?: string): Promise<string | undefined> {
469	  if (!email) return fallback;
470	  const resolved = await resolveHostContactByEmail(email).catch(() => null);
471	  if (resolved?.name && resolved.name.toLowerCase() !== email.toLowerCase()) return resolved.name;
472	  if (fallback && fallback.toLowerCase() !== email.toLowerCase()) return fallback;
473	  return resolved?.name ?? fallback ?? nameFromEmail(email);
474	}
475	
476	/**
477	 * Reflect an externally-cancelled invitation (e.g. dashboard cancel button) in any
478	 * draft that holds it: mark the guest cancelled + exclude them, so a later
479	 * reschedule/Update doesn't recreate their pass (F1).
480	 */
481	export async function markDraftGuestCancelledByInvitationId(invitationId: string): Promise<void> {
482	  if (!invitationId) return;
483	  const db = await getDb();
484	  const result = await db.execute({
485	    sql: `SELECT ical_uid FROM visit_drafts WHERE roster LIKE ?`,
486	    args: [`%"${invitationId}"%`],
487	  });
488	  for (const row of result.rows as unknown as { ical_uid: string }[]) {
489	    const draft = await getDraft(row.ical_uid);
490	    if (!draft) continue;
491	    let changed = false;
492	    for (const g of draft.roster) {
493	      if (g.invitationId === invitationId) {
494	        g.status = 'cancelled';
495	        g.include = false;
496	        g.invitationId = undefined;
497	        changed = true;
498	      }
499	    }
500	    if (changed) await upsertDraft(draft);
501	  }
502	}
503	
504	/**
505	 * Refresh only the event times on an existing draft (no-op if absent). Used by the
506	 * passive ingest on reschedule/redelivery — keeps times current WITHOUT touching the
507	 * host's curated roster.
508	 */
509	export async function touchDraftTimes(
510	  iCalUid: string,
511	  eventStart?: string,
512	  eventEnd?: string,
513	): Promise<void> {
514	  const db = await getDb();
515	  await db.execute({
516	    sql: `UPDATE visit_drafts SET event_start = ?, event_end = ?, updated_at = now()::text WHERE ical_uid = ?`,
517	    args: [eventStart ?? null, eventEnd ?? null, iCalUid],
518	  });
519	}
520	
521	/** Apply a host edit (per-guest fields / include toggle / visit location) and persist. */
522	export async function patchDraft(iCalUid: string, patch: DraftPatch | undefined): Promise<VisitDraft | null> {
523	  const draft = await getDraft(iCalUid);
524	  if (!draft) return null;
525	  if (patch?.location !== undefined) draft.location = patch.location;
526	  for (const gp of patch?.guests ?? []) {
527	    const guest = draft.roster.find((g) => g.email.toLowerCase() === gp.email.toLowerCase());
528	    if (!guest) continue;
529	    if (gp.include !== undefined) guest.include = gp.include;
530	    if (gp.name !== undefined) guest.name = gp.name;
531	    if (gp.phone !== undefined) guest.phone = gp.phone;
532	    if (gp.passTemplateKey !== undefined) guest.passTemplateKey = gp.passTemplateKey;
533	    if (gp.emailTemplateKey !== undefined) guest.emailTemplateKey = gp.emailTemplateKey;
534	  }
535	  await upsertDraft(draft);
536	  return draft;
537	}
538	
539	/** Record created invites back onto the draft (status + invitationId) and optionally new times. */
540	export async function markMaterialized(
541	  iCalUid: string,
542	  passes: { visitorEmail: string; invitationId: string }[],
543	  times?: { eventStart?: string; eventEnd?: string },
544	): Promise<void> {
545	  const draft = await getDraft(iCalUid);
546	  if (!draft) return;
547	  for (const pass of passes) {
548	    const guest = draft.roster.find((g) => g.email.toLowerCase() === pass.visitorEmail.toLowerCase());
549	    if (guest) {
550	      guest.invitationId = pass.invitationId;
551	      guest.status = 'sent';
552	    }
553	  }
554	  draft.materialized = true;
555	  if (times?.eventStart !== undefined) draft.eventStart = times.eventStart;
556	  if (times?.eventEnd !== undefined) draft.eventEnd = times.eventEnd;
557	  await upsertDraft(draft);
558	}
559	
560	// ─── Materialize ──────────────────────────────────────────────
561	
562	/**
563	 * Create one visitor invite per INCLUDED guest, honoring the host's overrides.
564	 * Reuses `createVisitorInvite` (the shared cross-channel entry) — no logic fork.
565	 * Caller is responsible for cancelling any prior invites and writing the
566	 * `calendar_event_links` ledger row (so dedup/reschedule converge).
567	 */
568	export async function materializeDraft(
569	  draft: VisitDraft,
570	  opts: { hostName?: string; rescheduled?: boolean } = {},
571	): Promise<{ invitationIds: string[]; passes: PassResult[] }> {
572	  // Pass duration must equal the event window — never guess (decision 2026-06-17).
573	  const window = resolveEventWindow(draft);
574	  if (!window) {
575	    console.warn(`[VisitDraft] materialize skipped for ${draft.iCalUid}: ${EVENT_TIME_MISSING}`);
576	    return { invitationIds: [], passes: [] };
577	  }
578	  const { start, end } = window;
579	
580	  const resolvedHost = draft.hostEmail
581	    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
582	    : null;
583	  // Prefer the Workspace-resolved name; only fall back to opts.hostName when it's
584	  // a real name (not the email the ID token gives us). Never show the email.
585	  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
586	  // On a reschedule, the guest already had a pass → frame the new one as updated.
587	  const emailOverride = opts.rescheduled ? { ...RESCHEDULED_EMAIL_OVERRIDE } : undefined;
588	
589	  const passes: PassResult[] = [];
590	  for (const guest of draft.roster) {
591	    if (!guest.include || !guest.email) continue;
592	    const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
593	    try {
594	      const result = await createVisitorInvite({
595	        visitorName,
596	        visitorEmail: guest.email,
597	        visitorPhone: guest.phone || undefined,
598	        purpose: draft.title,
599	        hostEmail: draft.hostEmail,
600	        hostEmployeeId: resolvedHost?.staff?.id,
601	        hostEmployeeName: hostName ?? draft.hostEmail,
602	        expectedDate: istDate(start),
603	        expectedTime: istTime(start),
604	        validFrom: start.toISOString(),
605	        validUntil: end.toISOString(),
606	        emailTemplateKey: guest.emailTemplateKey,
607	        emailTemplateOverride: emailOverride,
608	        passTemplateKey: guest.passTemplateKey,
609	        invitedVia: 'calendar',
610	        invitedBy: draft.hostEmail,
611	        approvalTier: 'invited',
612	        // The host explicitly included this guest in the add-on roster → that IS
613	        // the override for the same-workspace guard (F2).
614	        allowInternalColleague: true,
615	      });
616	      passes.push({
617	        visitorEmail: guest.email,
618	        visitorName,
619	        invitationId: result.invitationId,
620	        passUrl: result.qrUrl,
621	        status: 'sent',
622	      });
623	    } catch (err) {
624	      // One bad guest (e.g. past date) shouldn't sink the rest.
625	      console.warn(`[VisitDraft] invite for ${guest.email} failed:`, err);
626	    }
627	  }
628	  return { invitationIds: passes.map((p) => p.invitationId), passes };
629	}
630	
631	export interface ApplyResult {
632	  /** Every currently-active invitation id (for the ledger). */
633	  invitationIds: string[];
634	  /** Guests whose pass was created in THIS apply. */
635	  created: PassResult[];
636	  /** Guests whose pass was cancelled in THIS apply. */
637	  cancelled: { visitorEmail: string; invitationId: string }[];
638	  /** Guests we tried to send but couldn't (e.g. event time in the past). */
639	  failed: { visitorEmail: string; reason: string }[];
640	  draft: VisitDraft;
641	}
642	
643	/**
644	 * Reconcile the live passes to match the roster's include toggles (plan §1):
645	 *   include=true  & no active pass → create
646	 *   include=false & active pass    → cancel
647	 *   include=true  & active pass     → keep (a same-time edit; event-move reissue is
648	 *                                     handled separately in calendar-ingest)
649	 * Persists the draft (status + invitationId per guest, materialized flag). The
650	 * caller writes the `calendar_event_links` ledger from `invitationIds`.
651	 */
652	export async function applyDraft(draft: VisitDraft, opts: { hostName?: string } = {}): Promise<ApplyResult> {
653	  // Pass duration must equal the event window — never guess (decision 2026-06-17).
654	  // When the times are unavailable we still process cancellations, but refuse to
655	  // CREATE a pass with a wrong duration; those guests are reported as failed.
656	  const window = resolveEventWindow(draft);
657	  const start = window?.start;
658	  const end = window?.end;
659	  const resolvedHost = draft.hostEmail
660	    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
661	    : null;
662	  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
663	
664	  const created: PassResult[] = [];
665	  const cancelled: { visitorEmail: string; invitationId: string }[] = [];
666	  const failed: { visitorEmail: string; reason: string }[] = [];
667	
668	  for (const guest of draft.roster) {
669	    const hasActivePass = guest.status === 'sent' && !!guest.invitationId;
670	
671	    if (guest.include && !hasActivePass) {
672	      if (!start || !end) {
673	        // No reliable event window → don't issue a wrong-duration pass.
674	        failed.push({ visitorEmail: guest.email, reason: EVENT_TIME_MISSING });
675	        continue;
676	      }
677	      const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
678	      try {
679	        const result = await createVisitorInvite({
680	          visitorName,
681	          visitorEmail: guest.email,
682	          visitorPhone: guest.phone || undefined,
683	          purpose: draft.title,
684	          hostEmail: draft.hostEmail,
685	          hostEmployeeId: resolvedHost?.staff?.id,
686	          hostEmployeeName: hostName ?? draft.hostEmail,
687	          expectedDate: istDate(start),
688	          expectedTime: istTime(start),
689	          validFrom: start.toISOString(),
690	          validUntil: end.toISOString(),
691	          emailTemplateKey: guest.emailTemplateKey,
692	          passTemplateKey: guest.passTemplateKey,
693	          invitedVia: 'calendar',
694	          invitedBy: draft.hostEmail,
695	          approvalTier: 'invited',
696	          allowInternalColleague: true, // host-included guest = override (F2)
697	        });
698	        guest.invitationId = result.invitationId;
699	        guest.status = 'sent';
700	        created.push({ visitorEmail: guest.email, visitorName, invitationId: result.invitationId, passUrl: result.qrUrl, status: 'sent' });
701	      } catch (err) {
702	        const reason = err instanceof Error ? err.message : String(err);
703	        console.warn(`[VisitDraft] apply-create for ${guest.email} failed:`, reason);
704	        failed.push({ visitorEmail: guest.email, reason });
705	      }
706	    } else if (!guest.include && hasActivePass) {
707	      const id = guest.invitationId as string;
708	      const ok = await cancelInvitationById(id).catch((e) => {
709	        console.warn(`[VisitDraft] apply-cancel ${id} failed:`, e);
710	        return false;
711	      });
712	      if (ok) await notifyInviteCancelled(id, { cancelledBy: hostName, reason: 'The host cancelled your visitor pass.' });
713	      cancelled.push({ visitorEmail: guest.email, invitationId: id });
714	      guest.status = 'cancelled';
715	      guest.invitationId = undefined;
716	    }
717	  }
718	
719	  const invitationIds = draft.roster
720	    .filter((g) => g.status === 'sent' && g.invitationId)
721	    .map((g) => g.invitationId as string);
722	  draft.materialized = invitationIds.length > 0 || draft.materialized;
723	  await upsertDraft(draft);
724	  return { invitationIds, created, cancelled, failed, draft };
725	}
