// An invitation is "active" (could still be honoured at reception) when it isn't
// cancelled/rejected/completed — same set the cancel guard uses.
const ACTIVE_STATUS_SQL = `approval_status NOT IN ('cancelled', 'rejected', 'completed')`;

/**
 * Find an ACTIVE invitation for a visitor on a given date — used by the add-on to
 * adopt a pass already created through ANY channel (dashboard/Slack/Excel/prior
 * add-on) instead of offering a duplicate. Matches on visitor_email + expected_date
 * (IST date string). Most-recent first.
 */
export async function findActiveInvitationForVisitor(
  visitorEmail: string,
  expectedDate: string,
): Promise<VisitorInvitation | null> {
  if (!visitorEmail) return null;
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM visitor_invitations
