 *
 * Reused by the passive `classifyAttendees` (poll/.ics) AND the add-on roster
 * builder (sets each guest's DEFAULT toggle). `home_location_id` is admin-set.
 */
export function isVisitorAttendee(
  attendeeEmail: string | undefined,
  hostEmail: string | undefined,
  opts: { domains?: string[]; hostLocation?: string } = {},
): boolean {
  const email = attendeeEmail?.toLowerCase();
  if (!email) return false;
  const host = hostEmail?.toLowerCase();
  if (email === host) return false;
  if (inboxAddresses().includes(email)) return false;

  const domains = opts.domains ?? internalDomains();
  const isExternal = !domains.includes(domainOf(email));
  if (isExternal) return true;

  // Internal colleague → visitor only if positively placed at a different office.
  const hostLocation = opts.hostLocation
    ?? locationKey(host ? getStaffByContact({ email: host }) : undefined);
  const colleagueLocation = locationKey(getStaffByContact({ email }));
  if (!hostLocation || !colleagueLocation) return false; // unknown → assume local
  return colleagueLocation !== hostLocation;
}

/**
 * The same-workspace guard (F2): true when this visitor is an internal colleague
 * who should NOT normally get a pass — i.e. an internal-domain email at the SAME or
 * UNKNOWN home office as the host. External guests and different-office colleagues
 * return false (they legitimately get a pass). Empty/absent email → false (can't
 * identify → never block). Inverse of `isVisitorAttendee` restricted to internal.
 */
export function isSameWorkspaceLocalColleague(
  visitorEmail: string | undefined,
  hostEmail: string | undefined,
): boolean {
  const email = visitorEmail?.toLowerCase();
  if (!email) return false;
  if (!internalDomains().includes(domainOf(email))) return false; // external → allowed
  return !isVisitorAttendee(email, hostEmail); // internal + same/unknown office → block
}

function classifyAttendees(event: NormalizedCalendarEvent, domains: string[]): Classified {
  const organizerEmail = event.organizer?.email.toLowerCase();
  const hostLocation = locationKey(organizerEmail ? getStaffByContact({ email: organizerEmail }) : undefined);
  const visitors = event.attendees.filter((a) =>
    isVisitorAttendee(a.email, organizerEmail, { domains, hostLocation }),
  );
  return { host: event.organizer, visitors };
}

