  // Cross-channel dedup: a pass created via the dashboard (web) must be ADOPTED by
  // the add-on draft (Manage mode), not offered as a duplicate "Send".
  test('add-on draft adopts an existing pass instead of duplicating it', async () => {
    const { createVisitorInvite } = await import('./invite-manager');
    const { getOrCreateDraft } = await import('./visit-drafts');
    const { getCurrentISTDate } = await import('../../lib/time');

    const date = getCurrentISTDate();
    const guestEmail = `dedupe-${Date.now()}@external.com`;
    const created = await createVisitorInvite({
      visitorName: 'Dedupe Guest',
      visitorEmail: guestEmail,
      expectedDate: date,
      invitedVia: 'web',
      approvalTier: 'invited',
      approvalStatus: 'approved',
    });

    const draft = await getOrCreateDraft({
      iCalUid: `adopt-${Date.now()}@example.com`,
      hostEmail: 'host@appointy.com',
      attendees: [{ email: guestEmail, name: 'Dedupe Guest' }],
      eventStart: new Date(`${date}T10:00:00+05:30`).toISOString(),
      eventEnd: new Date(`${date}T11:00:00+05:30`).toISOString(),
    });

    const guest = draft.roster.find((g) => g.email === guestEmail);
    expect(guest?.status).toBe('sent');
    expect(guest?.invitationId).toBe(created.invitationId);
    expect(draft.materialized).toBe(true);
  });

  // Gap A: an adopted pass on an organizer-owned event gets a calendar_event_links
  // row (keyed on the real iCalUid) so the background watch can reschedule/cancel it.
  test('adopted pass on an organizer event is linked for lifecycle (then reschedules)', async () => {
    const { createVisitorInvite, reissueInvitation } = await import('./invite-manager');
    const { getOrCreateDraft } = await import('./visit-drafts');
    const { recordInvitationCalendarLink, ingestCalendarEvent } = await import('./calendar-ingest');
    const { getRelativeISTDate } = await import('../../lib/time');

    const date = getRelativeISTDate(1); // tomorrow → window is safely in the future
    const guestEmail = `link-${Date.now()}@external.com`;
    const uid = `link-${Date.now()}@example.com`;
    const start = new Date(`${date}T10:00:00+05:30`);
    const end = new Date(`${date}T11:00:00+05:30`);

    const created = await createVisitorInvite({
      visitorName: 'Link Guest', visitorEmail: guestEmail, expectedDate: date,
      invitedVia: 'web', approvalTier: 'invited', approvalStatus: 'approved',
    });

    const draft = await getOrCreateDraft({
      iCalUid: uid, hostEmail: 'host@appointy.com',
      attendees: [{ email: guestEmail, name: 'Link Guest' }],
      eventStart: start.toISOString(), eventEnd: end.toISOString(),
    });
    const sentIds = draft.roster.filter((g) => g.status === 'sent' && g.invitationId).map((g) => g.invitationId as string);
    expect(sentIds).toEqual([created.invitationId]);

    // Simulate the organizer-gated link the draft route writes.
    await recordInvitationCalendarLink({
      iCalUid: uid, organizerEmail: 'host@appointy.com', invitationIds: sentIds,
      source: 'addon-link', eventStart: start.toISOString(), eventEnd: end.toISOString(),
    });

    // Now a watch-driven move (new time) reschedules the linked invite (D8 reissue).
    void reissueInvitation; // (exercised indirectly by ingest's reschedule branch)
    const newStart = new Date(start.getTime() + 2 * 3600_000);
    const newEnd = new Date(end.getTime() + 2 * 3600_000);
    const moved = await ingestCalendarEvent({
      iCalUid: uid, sequence: 1, method: 'REQUEST', title: 'Visit',
      organizer: { email: 'host@appointy.com' },
      attendees: [{ email: guestEmail }],
      start: newStart, end: newEnd, source: 'oauth',
    });
    expect(moved.status).toBe('updated');
    expect(moved.invitationIds.length).toBe(1);
    expect(moved.invitationIds[0]).not.toBe(created.invitationId); // reissued, new id
  });

  // Regression: a pass already linked to event A must NOT be adopted by a NEW
  // event B for the same guest+date (no cross-event bleed → B stays in Setup mode).
  test('a pass linked to another event is not adopted by a new event', async () => {
    const { createVisitorInvite } = await import('./invite-manager');
    const { getOrCreateDraft } = await import('./visit-drafts');
    const { recordInvitationCalendarLink } = await import('./calendar-ingest');
    const { getRelativeISTDate } = await import('../../lib/time');

    const date = getRelativeISTDate(1);
    const guestEmail = `bleed-${Date.now()}@external.com`;
    const eventA = `A-${Date.now()}@example.com`;
    const eventB = `B-${Date.now()}@example.com`;
    const start = new Date(`${date}T10:00:00+05:30`);
    const end = new Date(`${date}T11:00:00+05:30`);

    const passA = await createVisitorInvite({
      visitorName: 'Bleed Guest', visitorEmail: guestEmail, expectedDate: date,
      invitedVia: 'web', approvalTier: 'invited', approvalStatus: 'approved',
    });
    // Link passA to event A.
    await recordInvitationCalendarLink({
      iCalUid: eventA, organizerEmail: 'host@appointy.com', invitationIds: [passA.invitationId],
      source: 'addon-link', eventStart: start.toISOString(), eventEnd: end.toISOString(),
    });

    // Open a DIFFERENT event B with the same guest + date.
    const draftB = await getOrCreateDraft({
      iCalUid: eventB, hostEmail: 'host@appointy.com',
      attendees: [{ email: guestEmail, name: 'Bleed Guest' }],
      eventStart: start.toISOString(), eventEnd: end.toISOString(),
    });
    const guestB = draftB.roster.find((g) => g.email === guestEmail);
    expect(guestB?.status).toBe('pending');     // NOT adopted
    expect(guestB?.invitationId).toBeUndefined();
    expect(draftB.materialized).toBe(false);    // Setup mode, shows "Send passes"
  });
});

