if (pathname === '/api/visitor/calendar/addon/draft' && method === 'POST') {
  const body = await readBodyJson(req);
  const iCalUid = String(body.iCalUid ?? '').trim();
  if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
  const attendees = Array.isArray(body.attendees)
    ? (body.attendees as { email: string; name?: string }[]).filter((a) => a && typeof a.email === 'string')
    : [];
  // Card-open path → trusted, complete attendee list → reconcile removals
  // (drop + cancel guests removed from the event). Plan §8B.
  const draft = await getOrCreateDraft({
    iCalUid,
    providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
    title: body.title ? String(body.title) : undefined,
    hostEmail: identity.email,
    attendees,
    eventStart: body.start ? String(body.start) : undefined,
    eventEnd: body.end ? String(body.end) : undefined,
    location: body.location ? String(body.location) : undefined,
  }, { reconcileRemovals: true });

  // Gap A — link this event for background lifecycle (move/delete via the watch),
  // but only when X is the event ORGANIZER (don't attach lifecycle to meetings
  // X was merely invited to) and a pass actually exists for it. Keyed on the
  // real iCalUid so the watch's ingest finds it. Reuses the D8 link writer.
  const organizerEmail = body.organizerEmail ? String(body.organizerEmail).toLowerCase() : '';
  const isOrganizer = !!organizerEmail && organizerEmail === identity.email.toLowerCase();
  const sentIds = draft.roster.filter((g) => g.status === 'sent' && g.invitationId).map((g) => g.invitationId as string);
  if (isOrganizer && sentIds.length > 0) {
    await recordInvitationCalendarLink({
      iCalUid,
      providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
      organizerEmail: identity.email,
      invitationIds: sentIds,
      source: 'addon-link',
      eventStart: draft.eventStart ?? null,
      eventEnd: draft.eventEnd ?? null,
    }).catch((e) => console.warn('[Addon] event link failed:', e));
  }

  // Gap C — tell the card whether background auto-sync (move/delete) is active.
  // Connected → seamless. Not connected → the card offers a one-tap Connect.
  const connected = await isCalendarConnected(identity.email).catch(() => false);
  const calendarSync = {
    connected,
    canConnect: isCalendarOAuthConfigured(),
    // Only meaningful to prompt when X owns the event (lifecycle attaches to it).
    relevant: isOrganizer,
    connectUrl: !connected && isCalendarOAuthConfigured()
      ? connectStartUrl({ email: identity.email })
      : undefined,
  };

  json(res, 200, { ...draft, calendarSync });
  return true;
}

// PATCH /addon/draft — persist a host edit (include toggle / name / phone / templates / location).
if (pathname === '/api/visitor/calendar/addon/draft' && method === 'PATCH') {
  const body = await readBodyJson(req);
  const iCalUid = String(body.iCalUid ?? '').trim();
  if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
  const updated = await patchDraft(iCalUid, body.patch as DraftPatch | undefined);
  if (!updated) { json(res, 404, { error: 'draft not found' }); return true; }
  json(res, 200, updated);
  return true;
}

