/// <reference types="bun" />
import { describe, test, expect } from 'bun:test';
import { buildRoster } from './visit-drafts';

const noPhone = async () => undefined;

describe('buildRoster', () => {
  test('drops the host, dedups case-insensitively, defaults include=true/pending', async () => {
    const roster = await buildRoster(
      [
        { email: 'Host@appointy.com', name: 'Host' },
        { email: 'guest@x.com', name: 'Guest One' },
        { email: 'GUEST@x.com' }, // duplicate of the above
        { email: 'two@y.com' },
      ],
      'host@appointy.com',
      noPhone,
    );
    expect(roster.map((g) => g.email)).toEqual(['guest@x.com', 'two@y.com']);
    expect(roster.every((g) => g.include)).toBe(true);
    expect(roster.every((g) => g.status === 'pending')).toBe(true);
  });

  test('derives a name from the email local-part when none is given', async () => {
    const roster = await buildRoster([{ email: 'jane.doe@x.com' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Jane Doe');
  });

  test('keeps a provided name (trimmed)', async () => {
    const roster = await buildRoster([{ email: 'g@x.com', name: '  Riya  ' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Riya');
  });

  test('injects phone from the lookup', async () => {
    const roster = await buildRoster(
      [{ email: 'g@x.com' }],
      undefined,
      async (email) => (email === 'g@x.com' ? '+91999' : undefined),
    );
    expect(roster[0]?.phone).toBe('+91999');
  });

  test('skips blank emails', async () => {
    const roster = await buildRoster([{ email: '' }, { email: 'ok@x.com' }], undefined, noPhone);
    expect(roster.map((g) => g.email)).toEqual(['ok@x.com']);
  });

  test('default toggle follows the includeDecider (same-workspace colleague pre-off)', async () => {
    // decider: external/different-office ON, internal same-office OFF.
    const decider = (email: string) => !email.endsWith('@appointy.com');
    const roster = await buildRoster(
      [{ email: 'guest@client.com' }, { email: 'colleague@appointy.com' }],
      'host@appointy.com',
      noPhone,
      decider,
    );
    const guest = roster.find((g) => g.email === 'guest@client.com');
    const colleague = roster.find((g) => g.email === 'colleague@appointy.com');
    expect(guest?.include).toBe(true);       // external → on
    expect(colleague?.include).toBe(false);  // same workspace → pre-off, still listed
    expect(roster.length).toBe(2);
  });
});

