  });

  test('derives a name from the email local-part when none is given', async () => {
    const roster = await buildRoster([{ email: 'jane.doe@x.com' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Jane Doe');
  });

  test('keeps a provided name (trimmed)', async () => {
    const roster = await buildRoster([{ email: 'g@x.com', name: '  Riya  ' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Riya');
  });

  test('injects phone from the lookup', async () => {
    const roster = await buildRoster(
      [{ email: 'g@x.com' }],
