  test('skips blank emails', async () => {
    const roster = await buildRoster([{ email: '' }, { email: 'ok@x.com' }], undefined, noPhone);
    expect(roster.map((g) => g.email)).toEqual(['ok@x.com']);
  });

  test('default toggle follows the includeDecider (same-workspace colleague pre-off)', async () => {
    // decider: external/different-office ON, internal same-office OFF.
    const decider = (email: string) => !email.endsWith('@appointy.com');
    const roster = await buildRoster(
      [{ email: 'guest@client.com' }, { email: 'colleague@appointy.com' }],
      'host@appointy.com',
      noPhone,
      decider,
    );
    const guest = roster.find((g) => g.email === 'guest@client.com');
    const colleague = roster.find((g) => g.email === 'colleague@appointy.com');
    expect(guest?.include).toBe(true);       // external → on
    expect(colleague?.include).toBe(false);  // same workspace → pre-off, still listed
    expect(roster.length).toBe(2);
  });
});

