// Regression: a default-OFF internal colleague must NOT inherit an unrelated
// same-day pass via the loose identity match. The bug showed a plain internal
// event as "Pass sent" + toggle-on for a workspace guest who had a pass from some
// other visit that day. Requires VISITOR_CALENDAR_INTERNAL_DOMAINS=appointy.com.
test('an internal colleague is not adopted by the loose identity match', async () => {
  const { createVisitorInvite } = await import('./invite-manager');
  const { getOrCreateDraft } = await import('./visit-drafts');
  const { getCurrentISTDate } = await import('../../lib/time');

  const date = getCurrentISTDate();
  // Same domain as the host → internal; no home office set → same/unknown office →
  // default-OFF (not a visitor by default).
  const colleagueEmail = `colleague-${Date.now()}@appointy.com`;
  // An unrelated active pass for this colleague on the same date (e.g. a different
  // visit), NOT linked to this event.
  await createVisitorInvite({
    visitorName: 'Colleague',
    visitorEmail: colleagueEmail,
    expectedDate: date,
    invitedVia: 'web',
    approvalTier: 'invited',
    approvalStatus: 'approved',
    allowInternalColleague: true,
  });

  const draft = await getOrCreateDraft({
    iCalUid: `internal-${Date.now()}@example.com`,
    hostEmail: 'host@appointy.com',
    attendees: [{ email: colleagueEmail, name: 'Colleague' }],
    eventStart: new Date(`${date}T10:00:00+05:30`).toISOString(),
    eventEnd: new Date(`${date}T11:00:00+05:30`).toISOString(),
  });

  const guest = draft.roster.find((g) => g.email === colleagueEmail);
  expect(guest?.internal).toBe(true);          // badged internal
  expect(guest?.include).toBe(false);          // toggle stays OFF
  expect(guest?.status).toBe('pending');       // NOT adopted
  expect(guest?.invitationId).toBeUndefined();
  expect(draft.materialized).toBe(false);      // plain event, no "Pass sent"
});

