  // POST /addon/send (and /addon/apply alias) — reconcile passes to the toggles:
  // create for newly-included guests, cancel for newly-excluded ones, keep the
  // rest. Used by both "Send passes" (Setup) and "Update passes" (Manage).
  if ((pathname === '/api/visitor/calendar/addon/send' || pathname === '/api/visitor/calendar/addon/apply') && method === 'POST') {
    const body = await readBodyJson(req);
    const iCalUid = String(body.iCalUid ?? '').trim();
    const draft = iCalUid ? await getDraft(iCalUid) : null;
    if (!draft) { json(res, 404, { error: 'draft not found' }); return true; }
    const result = await applyDraft(draft, { hostName: identity.name });
    // Record the ledger from the active set; draft_authoritative so passive
    // producers reissue/cancel from the curated roster on move/delete.
    await recordDraftMaterialization({
      iCalUid,
      providerEventId: draft.providerEventId,
      organizerEmail: identity.email,
      invitationIds: result.invitationIds,
      eventStart: draft.eventStart ?? null,
      eventEnd: draft.eventEnd ?? null,
    });
    json(res, 200, {
      iCalUid,
      created: result.created,
      cancelled: result.cancelled,
      failed: result.failed,
      activeCount: result.invitationIds.length,
      draft: result.draft,
    });
    return true;
  }

  // POST /addon/cancel-guest — cancel one guest's invite.
  if (pathname === '/api/visitor/calendar/addon/cancel-guest' && method === 'POST') {
    const body = await readBodyJson(req);
    const invitationId = String(body.invitationId ?? '').trim();
    if (!invitationId) { json(res, 422, { error: 'invitationId required' }); return true; }
    const cancelled = await cancelInvitationById(invitationId).catch(() => false);
    json(res, 200, { invitationId, cancelled });
    return true;
  }

  json(res, 404, { error: 'unknown add-on route' });
  return true;
}

// ── Calendar OAuth connect: kick off the flow ─────────────
// The Slack App Home / first-DM button points here with a signed `s` carrying
// the host's email (+ slack id). We verify it, then 302 to Google consent with
// login_hint pre-selecting the host's account.
if (pathname === '/api/visitor/calendar/connect/start' && method === 'GET') {
  if (!isCalendarOAuthConfigured()) {
    json(res, 503, { error: 'Calendar OAuth is not configured.' });
    return true;
  }
  const stateParam = typeof query.s === 'string' ? query.s : undefined;
  const payload = verifyCalendarState(stateParam);
  if (!payload || !stateParam) {
    json(res, 400, { error: 'Invalid or expired connect link. Please reopen it from Slack.' });
    return true;
  }
  const url = buildCalendarAuthUrl(stateParam, payload.email);

