// 3) Self-heal: a stored 'sent' guest must still resolve to an ACTIVE invitation.
// The load path otherwise trusts the persisted status blindly, so a draft that was
// ever written 'sent' (e.g. a wrongly-adopted or since-cancelled/deleted pass)
// shows "Pass sent" forever even though no real pass backs it. If the invitation
// is gone, drop the claim and fall back to the fresh classifier default so the
// card reflects reality (internal colleague → toggle off).
const builtByEmail: Record<string, DraftGuest> = {};
for (const g of built.roster) builtByEmail[g.email.toLowerCase()] = g;
for (const g of roster) {
  if (g.status !== 'sent' || !g.invitationId) continue;
  const active = await getActiveInvitationById(g.invitationId).catch(() => null);
  if (active) continue;
  console.log(`[VisitDraft] guest ${g.email} stored 'sent' but invite ${g.invitationId} is gone → resetting to pending`);
  g.status = 'pending';
  g.invitationId = undefined;
  g.include = builtByEmail[g.email.toLowerCase()]?.include ?? g.include;
}

