input.new_string:
// Regression: a draft persisted with a phantom 'sent' (invitation no longer
// exists) must self-heal on reopen — drop the "Pass sent" claim, reset to the
// classifier default, and fall back to Setup mode. This is why a plain internal
// event kept showing "Pass sent" on every open: the bad status was baked into the
// visit_drafts row and the load path trusted it blindly.
test('a phantom sent guest self-heals to pending on reopen', async () => {
  const { upsertDraft, getOrCreateDraft } = await import('./visit-drafts');
  const { getCurrentISTDate } = await import('../../lib/time');

  const date = getCurrentISTDate();
  const colleagueEmail = `phantom-${Date.now()}@appointy.com`;
  const uid = `phantom-${Date.now()}@example.com`;
  const start = new Date(`${date}T10:00:00+05:30`).toISOString();
  const end = new Date(`${date}T11:00:00+05:30`).toISOString();

  // Persist a draft as if a phantom pass had been written for an internal guest.
  await upsertDraft({
    iCalUid: uid,
    tenantId: 'appointy',
    hostEmail: 'host@appointy.com',
    roster: [{
      email: colleagueEmail, name: 'Phantom', include: true, internal: true,
      status: 'sent', invitationId: 'does-not-exist-12345',
    }],
    eventStart: start, eventEnd: end, materialized: true,
  });

  const draft = await getOrCreateDraft({
    iCalUid: uid, hostEmail: 'host@appointy.com',
    attendees: [{ email: colleagueEmail, name: 'Phantom' }],
    eventStart: start, eventEnd: end,
  });

  const guest = draft.roster.find((g) => g.email === colleagueEmail);
  expect(guest?.status).toBe('pending');       // phantom 'sent' cleared
  expect(guest?.invitationId).toBeUndefined();
  expect(guest?.include).toBe(false);          // back to classifier default (internal → off)
  expect(draft.materialized).toBe(false);      // back to Setup mode
});

// Gap A: an adopted pass on an organizer-owned event gets a calendar_event_links

