function internalDomains(override?: string[]): string[] {
  if (override?.length) return override.map((d) => d.toLowerCase());
  const list = (process.env.VISITOR_CALENDAR_INTERNAL_DOMAINS ?? process.env.GOOGLE_CALENDAR_DOMAIN ?? '')
    .split(',')
    .map((d) => d.trim().toLowerCase())
    .filter(Boolean);
  return list;
}

/** Our own magic mailbox(es); always stripped from attendees. */
function inboxAddresses(): string[] {
  return (process.env.VISITOR_CALENDAR_INBOX_ADDRESS ?? '')
    .split(',')
    .map((a) => a.trim().toLowerCase())
    .filter(Boolean);
}

function domainOf(email: string): string {
  return email.split('@')[1]?.toLowerCase() ?? '';
}

