/**
 * Remove a (now-cancelled) invitation id from every calendar_event_links row that
 * references it, so a later reschedule can't resurrect it. Belt-and-suspenders for
 * the reschedule active-filter (F1). Called when a pass is cancelled outside the
 * add-on (e.g. the dashboard cancel button).
 */
export async function unlinkInvitationFromCalendar(invitationId: string): Promise<void> {
  if (!invitationId) return;
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT ical_uid, invitation_ids FROM calendar_event_links WHERE invitation_ids LIKE ?`,
    args: [`%"${invitationId}"%`],
  });
  for (const row of result.rows as unknown as { ical_uid: string; invitation_ids: string | null }[]) {
    const remaining = parseInvitationIds(row.invitation_ids).filter((id) => id !== invitationId);
    await db.execute({
      sql: `UPDATE calendar_event_links SET invitation_ids = ?, updated_at = now()::text WHERE ical_uid = ?`,
      args: [JSON.stringify(remaining), row.ical_uid],
    });
  }
}

