test('a phantom sent guest self-heals to pending on reopen', async () => {
  const { createVisitorInvite } = await import('./invite-manager');
  const { upsertDraft, getOrCreateDraft } = await import('./visit-drafts');
  const { recordInvitationCalendarLink, getLinkedInvitationIds } = await import('./calendar-ingest');
  const { getCurrentISTDate } = await import('../../lib/time');

  const date = getCurrentISTDate();
  const colleagueEmail = `phantom-${Date.now()}@appointy.com`;
  const uid = `phantom-${Date.now()}@example.com`;
  const start = new Date(`${date}T10:00:00+05:30`).toISOString();
  const end = new Date(`${date}T11:00:00+05:30`).toISOString();

  // The exact failing scenario: a STILL-ACTIVE pass for the colleague from another
  // channel (web), that the buggy first open both adopted AND linked to this event.
  // An active + linked check alone can't catch it — only invited_via != 'calendar'.
  const borrowed = await createVisitorInvite({
    visitorName: 'Phantom', visitorEmail: colleagueEmail, expectedDate: date,
    invitedVia: 'web', approvalTier: 'invited', approvalStatus: 'approved',
    allowInternalColleague: true,
  });
  await upsertDraft({
    iCalUid: uid,
    tenantId: 'appointy',
    hostEmail: 'host@appointy.com',
    roster: [{
      email: colleagueEmail, name: 'Phantom', include: true, internal: true,
      status: 'sent', invitationId: borrowed.invitationId,
    }],
    eventStart: start, eventEnd: end, materialized: true,
  });
  await recordInvitationCalendarLink({
    iCalUid: uid, organizerEmail: 'host@appointy.com', invitationIds: [borrowed.invitationId],
    source: 'addon-link', eventStart: start, eventEnd: end,
  });

  const draft = await getOrCreateDraft({
    iCalUid: uid, hostEmail: 'host@appointy.com',
    attendees: [{ email: colleagueEmail, name: 'Phantom' }],
    eventStart: start, eventEnd: end,
  });

  const guest = draft.roster.find((g) => g.email === colleagueEmail);
  expect(guest?.status).toBe('pending');       // phantom 'sent' cleared
  expect(guest?.invitationId).toBeUndefined();
  expect(guest?.include).toBe(false);          // back to classifier default (internal → off)
  expect(draft.materialized).toBe(false);      // back to Setup mode
  // The stale event→pass link is dropped so a later move/delete can't touch it.
  expect(await getLinkedInvitationIds(uid)).not.toContain(borrowed.invitationId);
});

