function onReviewSend(e) {
  var iCalUid = e.parameters.iCalUid;
  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
  var inputs = formInputs_(e);
  var included = [];
  var excluded = [];
  for (var i = 0; i < emails.length; i++) {
    var em = emails[i];
    var on = formValue_(inputs['inc_' + em]) === 'on';
    var name = formValue_(inputs['name_' + em]) || em;
    (on ? included : excluded).push({ email: em, name: name });
  }
  if (!included.length) return notify_('Turn on at least one guest before sending.');
  return CardService.newActionResponseBuilder()
    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
    .build();
}

function buildConfirmCard_(params, included, excluded) {
  var card = CardService.newCardBuilder()
    .setHeader(CardService.newCardHeader()
      .setTitle('Send ' + included.length + ' pass' + (included.length > 1 ? 'es' : '') + '?')
      .setImageUrl(ADDON_ICON_URL));
  var sec = CardService.newCardSection().setHeader('These guests get a pass');
  for (var i = 0; i < included.length; i++) {
    sec.addWidget(CardService.newDecoratedText()
      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
      .setText(included[i].name)
      .setBottomLabel(included[i].email)
      .setWrapText(true));
  }
  card.addSection(sec);
  if (excluded.length) {
    var ex = CardService.newCardSection().setHeader('Skipped (no pass / cancelled if sent before)');
    for (var j = 0; j < excluded.length; j++) {
      ex.addWidget(CardService.newDecoratedText()
        .setText(excluded[j].name).setBottomLabel(excluded[j].email).setWrapText(true));
    }
    card.addSection(ex);
  }

  // Email section: template picker (only when there's a real choice) + preview. The
  // picker is per-send (one template for the whole batch); preview opens the REAL
  // branded HTML for the first included guest. Both read/write the same draft, so
  // pick → preview → send stays consistent.
  var templates = [];
  try { templates = JSON.parse(params.templates || '[]'); } catch (err) { templates = []; }
  var emailSec = CardService.newCardSection().setHeader('Email');
  if (templates.length >= 2) {
    var picker = CardService.newSelectionInput()
      .setType(CardService.SelectionInputType.DROPDOWN)
      .setTitle('Template')
      .setFieldName('email_template');
    var current = params.currentTemplate || '';
    for (var t = 0; t < templates.length; t++) {
      var tmpl = templates[t];
      var selected = current ? (tmpl.key === current) : (tmpl.isDefault === true);
      picker.addItem(tmpl.name || tmpl.key, tmpl.key, selected);
    }
    emailSec.addWidget(picker);
  }
  emailSec.addWidget(CardService.newTextButton()
    .setText('Preview email')
    .setOnClickAction(CardService.newAction().setFunctionName('onPreview').setParameters(params)));
  card.addSection(emailSec);

  card.setFixedFooter(CardService.newFixedFooter()
    .setPrimaryButton(CardService.newTextButton()
      .setText('Send passes')
      .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
      .setBackgroundColor(BRAND_COLOR)
      .setOnClickAction(CardService.newAction().setFunctionName('onSaveAndSend').setParameters(params)))
    .setSecondaryButton(CardService.newTextButton()
      .setText('Back')
      .setOnClickAction(CardService.newAction().setFunctionName('onConfirmBack').setParameters(params))));
  return card.build();
}

