  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
}
function formValue_(input) {
  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
    return input.stringInputs.value[0];
  }
  return '';

