// Resolve the event from the Calendar API, tolerating transient 404s. A freshly
// created event is eventually-consistent — Events.get can 404 for a second or two
// after the user adds it — and this is our ONLY source of event start/end (the add-on
// payload carries attendees but no times). So a miss here means a draft saved without
// times and a send that fails with EVENT_TIME_MISSING. Retry with backoff (~2.7s
// total) across the event's calendar and the primary calendar. Returns the event or null.
function fetchEventWithRetry_(calendarId, eventId) {
  var targets = [];
  if (calendarId) targets.push(calendarId);
  if (calendarId !== 'primary') targets.push('primary');
  var backoffs = [300, 700, 1500]; // waits AFTER attempts 0,1,2 (4 attempts total)
  for (var attempt = 0; attempt < 4; attempt++) {
    for (var t = 0; t < targets.length; t++) {
      try {
        var ev = Calendar.Events.get(targets[t], eventId);
        if (ev) return ev;
      } catch (err) {
        // 404 / transient → fall through to the next target / retry.
      }
    }
    if (attempt < backoffs.length) Utilities.sleep(backoffs[attempt]);
  }
  return null;

