473	// ── Actions ───────────────────────────────────────────────
474	// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
475	function cardDeriveName_(email) {
476	  var local = (email.split('@')[0] || email);
477	  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
478	}
479	
480	var _peopleWarmed = false;
481	function peopleSearch_(path, email) {
482	  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
483	  var base = 'https://people.googleapis.com/v1/';
484	  // searchContacts/otherContacts.search require a warmup (empty-query) call first.
485	  if (!_peopleWarmed) {
486	    UrlFetchApp.fetch(base + 'people:searchContacts?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
487	    UrlFetchApp.fetch(base + 'otherContacts:search?query=&readMask=names,emailAddresses', { headers: headers, muteHttpExceptions: true });
488	    _peopleWarmed = true;
489	    Utilities.sleep(200);
490	  }
491	  var url = base + path + '?query=' + encodeURIComponent(email) + '&readMask=names,emailAddresses';
492	  var resp = UrlFetchApp.fetch(url, { headers: headers, muteHttpExceptions: true });
493	  if (resp.getResponseCode() !== 200) return '';
494	  var results = (JSON.parse(resp.getContentText()).results) || [];
495	  for (var i = 0; i < results.length; i++) {
496	    var person = results[i].person || {};
497	    var emails = person.emailAddresses || [];
498	    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
499	    if (match && person.names && person.names.length) return person.names[0].displayName || '';
500	  }
501	  return '';
502	}
503	
504	function resolveContactName_(email) {
505	  try {
506	    return peopleSearch_('people:searchContacts', email) || peopleSearch_('otherContacts:search', email);
507	  } catch (err) {
508	    return '';
509	  }
510	}
511	
512	// For each guest whose name is still auto-derived, look up the real contact name
513	// and PATCH it onto the draft (so subsequent opens skip the lookup). Mutates roster.
514	function resolveAndStoreNames_(iCalUid, roster) {
515	  var patches = [];
516	  for (var i = 0; i < roster.length; i++) {
517	    var g = roster[i];
518	    var looksDerived = !g.name || g.name === cardDeriveName_(g.email);
519	    if (!looksDerived) continue;
520	    var resolved = resolveContactName_(g.email);
521	    if (resolved && resolved !== g.name) {
522	      g.name = resolved;                       // reflect immediately in this render
523	      patches.push({ email: g.email, name: resolved });
524	    }
525	  }
526	  if (patches.length) {
527	    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
528	  }
529	}
