531	// Review step: persist edits, then push a textual confirm card. Cards can't
532	// render HTML inline (that's the "Preview email" overlay link), so the review
533	// here is the recipient list + what will happen — the guard before sending.
534	function onReviewSend(e) {
535	  var iCalUid = e.parameters.iCalUid;
536	  patchFromForm_(iCalUid, e); // persist toggles/names/phones BEFORE leaving the form card
537	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
538	  var inputs = formInputs_(e);
539	  var included = [];
540	  var excluded = [];
541	  for (var i = 0; i < emails.length; i++) {
542	    var em = emails[i];
543	    var on = formValue_(inputs['inc_' + em]) === 'on';
544	    var name = formValue_(inputs['name_' + em]) || em;
545	    (on ? included : excluded).push({ email: em, name: name });
546	  }
547	  if (!included.length) return notify_('Turn on at least one guest before sending.');
548	  return CardService.newActionResponseBuilder()
549	    .setNavigation(CardService.newNavigation().pushCard(buildConfirmCard_(e.parameters, included, excluded)))
550	    .build();
551	}
