553	function buildConfirmCard_(params, included, excluded) {
554	  // Thread the first included guest to the confirm card's actions — the per-guest
555	  // switches don't exist here, so onPreview can't re-derive the target from the form.
556	  params.previewEmail = included.length ? included[0].email : '';
557	  var card = CardService.newCardBuilder()
558	    .setHeader(CardService.newCardHeader()
559	      .setTitle('Send ' + included.length + ' pass' + (included.length > 1 ? 'es' : '') + '?')
560	      .setImageUrl(ADDON_ICON_URL));
561	  var sec = CardService.newCardSection().setHeader('These guests get a pass');
562	  for (var i = 0; i < included.length; i++) {
563	    sec.addWidget(CardService.newDecoratedText()
564	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
565	      .setText(included[i].name)
566	      .setBottomLabel(included[i].email)
567	      .setWrapText(true));
568	  }
569	  card.addSection(sec);
570	  if (excluded.length) {
