415	/**
416	 * Ingest one normalized calendar event into the visitor system.
417	 * Idempotent on `iCalUid`; safe to call repeatedly with redeliveries.
418	 */
419	export async function ingestCalendarEvent(
420	  event: NormalizedCalendarEvent,
421	  opts: IngestOptions = {},
422	): Promise<IngestResult> {
423	  const tenantId = opts.tenantId ?? event.tenantId ?? DEFAULT_TENANT_ID;
424	  const domains = internalDomains(opts.internalDomains);
425	  const uid = event.iCalUid;
426	
427	  if (!uid) {
428	    return { status: 'skipped', reason: 'missing iCalUid', iCalUid: '', invitationIds: [] };
429	  }
430	
431	  // Look up by iCalUID; fall back to the provider event id for cancellations,
432	  // which Google often delivers with only `id` + `status` (no iCalUID).
433	  let existing = await getCalendarLink(uid);
434	  if (!existing && event.providerEventId) {
435	    existing = await getCalendarLinkByProviderEventId(event.providerEventId);
436	  }
437	  // Always write under the link's real key (uid may be event.id on a cancel).
438	  const linkUid = existing?.ical_uid ?? uid;
439	
440	  // ── Cancellation ──
441	  if (event.method === 'CANCEL') {
442	    if (!existing || existing.status === 'cancelled') {
443	      return { status: 'skipped', reason: 'cancel for unknown/already-cancelled event', iCalUid: linkUid, invitationIds: [] };
444	    }
445	    const ids = parseInvitationIds(existing.invitation_ids);
446	    for (const id of ids) {
447	      const cancelled = await cancelInvitationById(id).catch((e) => {
448	        console.warn(`[CalendarIngest] cancel ${id} failed:`, e);
449	        return false;
450	      });
451	      // The host deleted the meeting → email the guest their visit is cancelled.
452	      if (cancelled) await notifyInviteCancelled(id, { reason: 'The meeting was cancelled on the calendar.' });
453	    }
454	    await upsertCalendarLink({
455	      iCalUid: linkUid,
456	      sequence: Math.max(event.sequence, existing.sequence),
457	      source: event.source,
458	      organizerEmail: event.organizer?.email,
459	      invitationIds: ids,
460	      status: 'cancelled',
461	      providerEventId: event.providerEventId,
462	    });
463	    await emitIngested(event, tenantId, ids, 'cancelled');
464	    return { status: 'cancelled', iCalUid: linkUid, invitationIds: ids };
465	  }
466	
467	  const startISO = event.start ? event.start.toISOString() : null;
468	  const endISO = event.end ? event.end.toISOString() : null;
469	
470	  // ── Update to an event we've already seen ──
471	  if (existing) {
472	    const timeChanged = (existing.event_start ?? null) !== startISO || (existing.event_end ?? null) !== endISO;
473	    // No time move (and not un-cancelling) → nothing visitor-facing to do.
474	    if (existing.status !== 'cancelled' && !timeChanged) {
475	      return { status: 'duplicate', iCalUid: uid, invitationIds: parseInvitationIds(existing.invitation_ids) };
476	    }
477	    // Reschedule: only move passes that are STILL ACTIVE. A pass an admin cancelled
478	    // (via the dashboard) must NOT be resurrected at the new time (F1). Capture the
479	    // active set BEFORE cancelling the old passes.
480	    const oldIds = parseInvitationIds(existing.invitation_ids);
481	    const activeOldIds = new Set(await filterActiveInvitationIds(oldIds).catch(() => oldIds));
482	    for (const id of oldIds) {
483	      await cancelInvitationById(id).catch((e) => console.warn(`[CalendarIngest] cancel-on-reschedule ${id} failed:`, e));
484	    }
485	
486	    // Draft-authoritative events re-issue from the host's CURATED roster, not raw
487	    // attendees — otherwise a reschedule would wipe the host's customization. Every
488	    // other (non-curated) event takes the original path below, unchanged.
489	    let rescheduledIds: string[];
490	    let rescheduleReason: string | undefined;
491	    if (existing.draft_authoritative) {
492	      const draft = await getDraft(linkUid);
493	      if (draft) {
494	        // Don't reissue a guest whose pass was externally cancelled before the move:
495	        // a guest who HAD a pass (status 'sent' + id) that's no longer active is
496	        // excluded from the reissue. New/uncancelled included guests are unaffected.
497	        for (const g of draft.roster) {
498	          if (g.status === 'sent' && g.invitationId && !activeOldIds.has(g.invitationId)) {
499	            g.include = false;
500	          }
501	        }
502	      }
503	      if (draft && draft.roster.some((g) => g.include)) {
504	        const mat = await materializeDraft(
505	          { ...draft, eventStart: startISO ?? draft.eventStart, eventEnd: endISO ?? draft.eventEnd },
506	          { rescheduled: true },
507	        );
508	        rescheduledIds = mat.invitationIds;
509	        await markMaterialized(linkUid, mat.passes, {
510	          eventStart: startISO ?? undefined,
511	          eventEnd: endISO ?? undefined,
512	        });
513	      } else {
514	        rescheduledIds = [];
515	        rescheduleReason = 'draft has no included guests';
516	      }
517	    } else if (activeOldIds.size > 0) {
518	      // Tracked event with linked invites but NO draft = the Slack-self-host D8
519	      // path (event created via the host's OAuth). Reissue ONLY the still-active
520	      // invitations at the new time from the invitation record itself.
521	      const newIds: string[] = [];
522	      for (const oldId of oldIds) {
523	        if (!activeOldIds.has(oldId)) continue; // cancelled → not reissued
524	        const fresh = await reissueInvitation(oldId, startISO ?? undefined, endISO ?? undefined)
525	          .catch((e) => { console.warn(`[CalendarIngest] reissue ${oldId} failed:`, e); return null; });
526	        if (fresh) newIds.push(fresh);
527	      }
528	      rescheduledIds = newIds;
529	      rescheduleReason = newIds.length === 0 ? 'reissue produced no invites' : undefined;
530	    } else {
531	      // Non-authoritative, no linked invites (never sent) → auto-send is off, so
532	      // there's nothing to move. Keep the draft's times fresh; nothing to create.
533	      await touchDraftTimes(linkUid, startISO ?? undefined, endISO ?? undefined);
534	      rescheduledIds = [];
535	      rescheduleReason = 'auto-send disabled — draft only, awaiting host send';
536	    }
537	
538	    await upsertCalendarLink({
539	      iCalUid: linkUid,
540	      sequence: event.sequence,
541	      source: event.source,
542	      organizerEmail: event.organizer?.email,
543	      invitationIds: rescheduledIds,
544	      status: 'active',
545	      eventStart: startISO,
546	      eventEnd: endISO,
547	      providerEventId: event.providerEventId,
548	      draftAuthoritative: !!existing.draft_authoritative,
549	    });
550	    if (rescheduledIds.length === 0) {
551	      return { status: 'skipped', reason: rescheduleReason ?? 'reschedule produced no invites', iCalUid: linkUid, invitationIds: [] };
552	    }
553	    await emitIngested(event, tenantId, rescheduledIds, 'created');
554	    return { status: 'updated', reason: 'rescheduled', iCalUid: linkUid, invitationIds: rescheduledIds };
555	  }
556	
557	  // ── New event ──
558	  // No auto-send (product decision 2026-06-17): passive producers build a Visit
559	  // Draft for the host to curate + send from the add-on. Invites are created only
560	  // via /addon/send (or the draft-authoritative reschedule above, for sent passes).
561	  // No calendar_event_links row is written here — that ledger is for sent events.
562	  const drafted = await draftFromEvent(event, domains, tenantId);
563	  await emitIngested(event, tenantId, [], drafted.drafted ? 'drafted' : 'skipped');
564	  return {
565	    status: drafted.drafted ? 'drafted' : 'skipped',
566	    reason: drafted.reason,
567	    iCalUid: uid,
568	    invitationIds: [],
569	  };
570	}
571	
572	/**
573	 * No-auto-send model (2026-06-17): classify attendees and build (or refresh) the
574	 * Visit Draft for the host to curate + send in the add-on. Does NOT create invites.
575	 * Returns `drafted: false` with a reason when the event isn't an in-person visit.
576	 */
577	async function draftFromEvent(
578	  event: NormalizedCalendarEvent,
579	  domains: string[],
580	  tenantId: string,
581	): Promise<{ drafted: boolean; reason?: string }> {
582	  const { host, visitors } = classifyAttendees(event, domains);
583	
584	  if (!host?.email) return { drafted: false, reason: 'no organizer/host' };
585	  // Host must be internal — otherwise this is an outside party inviting our
586	  // mailbox, not an employee hosting a visit. Forgery/irrelevance guard.
587	  if (domains.length && !domains.includes(domainOf(host.email))) {
588	    return { drafted: false, reason: `organizer ${host.email} not on an internal domain` };
589	  }
590	  if (visitors.length === 0) {
591	    return { drafted: false, reason: 'no external attendees (not an in-person visit)' };
592	  }
593	
594	  // Build the draft from the classified visitors (host already excluded). Non-
595	  // destructive: getOrCreateDraft keeps any roster the host has already curated.
596	  await getOrCreateDraft({
597	    iCalUid: event.iCalUid,
598	    tenantId,
599	    providerEventId: event.providerEventId,
600	    title: event.title,
601	    hostEmail: host.email,
602	    attendees: visitors,
603	    eventStart: event.start?.toISOString(),
604	    eventEnd: event.end?.toISOString(),
605	    location: event.location,
606	  });
607	  // Keep times fresh on redelivery/reschedule without clobbering host roster edits.
608	  await touchDraftTimes(event.iCalUid, event.start?.toISOString(), event.end?.toISOString());
609	  return { drafted: true };
610	}
611	
612	// ─── Automation surface (typed emit point, single drop-in) ────
613	// Per CLAUDE.md "build for the automation surface": one clear emit per state
614	// transition with a typed payload. NOT registered as a flow-pack trigger yet.
615	
616	interface CalendarIngestedPayload extends Record<string, unknown> {
617	  tenantId: string;
618	  iCalUid: string;
619	  source: CalendarEventSource;
620	  outcome: 'created' | 'cancelled' | 'drafted' | 'skipped';
621	  invitationIds: string[];
622	  title?: string;
623	  organizerEmail?: string;
624	  visitorEmails: string[];
625	}
626	
627	async function emitIngested(
628	  event: NormalizedCalendarEvent,
629	  tenantId: string,
630	  invitationIds: string[],
631	  outcome: 'created' | 'cancelled' | 'drafted' | 'skipped',
632	): Promise<void> {

