// ─── Main entry point ─────────────────────────────────────────

/**
 * Ingest one normalized calendar event into the visitor system.
 * Idempotent on `iCalUid`; safe to call repeatedly with redeliveries.
 */
export async function ingestCalendarEvent(
  event: NormalizedCalendarEvent,
  opts: IngestOptions = {},
): Promise<IngestResult> {
  const tenantId = opts.tenantId ?? event.tenantId ?? DEFAULT_TENANT_ID;
  const domains = internalDomains(opts.internalDomains);
  const uid = event.iCalUid;

  if (!uid) {
    return { status: 'skipped', reason: 'missing iCalUid', iCalUid: '', invitationIds: [] };
  }

  // Look up by iCalUID; fall back to the provider event id for cancellations,
  // which Google often delivers with only `id` + `status` (no iCalUID).
  let existing = await getCalendarLink(uid);
  if (!existing && event.providerEventId) {
    existing = await getCalendarLinkByProviderEventId(event.providerEventId);
  }
  // Always write under the link's real key (uid may be event.id on a cancel).
  const linkUid = existing?.ical_uid ?? uid;

  // ── Cancellation ──
  if (event.method === 'CANCEL') {
    if (!existing || existing.status === 'cancelled') {
      return { status: 'skipped', reason: 'cancel for unknown/already-cancelled event', iCalUid: linkUid, invitationIds: [] };
    }
    const ids = parseInvitationIds(existing.invitation_ids);
    for (const id of ids) {
      const cancelled = await cancelInvitationById(id).catch((e) => {
        console.warn(`[CalendarIngest] cancel ${id} failed:`, e);
        return false;
      });
      // The host deleted the meeting → email the guest their visit is cancelled.
      if (cancelled) await notifyInviteCancelled(id, { reason: 'The meeting was cancelled on the calendar.' });
    }
    await upsertCalendarLink({
      iCalUid: linkUid,
      sequence: Math.max(event.sequence, existing.sequence),
      source: event.source,
      organizerEmail: event.organizer?.email,
      invitationIds: ids,
      status: 'cancelled',
      providerEventId: event.providerEventId,
    });
    await emitIngested(event, tenantId, ids, 'cancelled');
    return { status: 'cancelled', iCalUid: linkUid, invitationIds: ids };
  }

  const startISO = event.start ? event.start.toISOString() : null;
  const endISO = event.end ? event.end.toISOString() : null;

  // ── Update to an event we've already seen ──
  if (existing) {
    const timeChanged = (existing.event_start ?? null) !== startISO || (existing.event_end ?? null) !== endISO;
    // No time move (and not un-cancelling) → nothing visitor-facing to do.
    if (existing.status !== 'cancelled' && !timeChanged) {
      return { status: 'duplicate', iCalUid: uid, invitationIds: parseInvitationIds(existing.invitation_ids) };
    }
    // Reschedule: only move passes that are STILL ACTIVE. A pass an admin cancelled
    // (via the dashboard) must NOT be resurrected at the new time (F1). Capture the
    // active set BEFORE cancelling the old passes.
    const oldIds = parseInvitationIds(existing.invitation_ids);
    const activeOldIds = new Set(await filterActiveInvitationIds(oldIds).catch(() => oldIds));
    for (const id of oldIds) {
      await cancelInvitationById(id).catch((e) => console.warn(`[CalendarIngest] cancel-on-reschedule ${id} failed:`, e));
    }

    // Draft-authoritative events re-issue from the host's CURATED roster, not raw
    // attendees — otherwise a reschedule would wipe the host's customization. Every
    // other (non-curated) event takes the original path below, unchanged.
    let rescheduledIds: string[];
    let rescheduleReason: string | undefined;
    if (existing.draft_authoritative) {
      const draft = await getDraft(linkUid);
      if (draft) {
        // Don't reissue a guest whose pass was externally cancelled before the move:
        // a guest who HAD a pass (status 'sent' + id) that's no longer active is
        // excluded from the reissue. New/uncancelled included guests are unaffected.
        for (const g of draft.roster) {
          if (g.status === 'sent' && g.invitationId && !activeOldIds.has(g.invitationId)) {
            g.include = false;
          }
        }
      }
      if (draft && draft.roster.some((g) => g.include)) {
        const mat = await materializeDraft(
          { ...draft, eventStart: startISO ?? draft.eventStart, eventEnd: endISO ?? draft.eventEnd },
          { rescheduled: true },
        );
        rescheduledIds = mat.invitationIds;
        await markMaterialized(linkUid, mat.passes, {
          eventStart: startISO ?? undefined,
          eventEnd: endISO ?? undefined,
        });
      } else {
        rescheduledIds = [];
        rescheduleReason = 'draft has no included guests';
      }
    } else if (activeOldIds.size > 0) {
      // Tracked event with linked invites but NO draft = the Slack-self-host D8
      // path (event created via the host's OAuth). Reissue ONLY the still-active
      // invitations at the new time from the invitation record itself.
      const newIds: string[] = [];
      for (const oldId of oldIds) {
        if (!activeOldIds.has(oldId)) continue; // cancelled → not reissued
        const fresh = await reissueInvitation(oldId, startISO ?? undefined, endISO ?? undefined)
          .catch((e) => { console.warn(`[CalendarIngest] reissue ${oldId} failed:`, e); return null; });
        if (fresh) newIds.push(fresh);
      }
      rescheduledIds = newIds;
      rescheduleReason = newIds.length === 0 ? 'reissue produced no invites' : undefined;
    } else {
      // Non-authoritative, no linked invites (never sent) → auto-send is off, so
      // there's nothing to move. Keep the draft's times fresh; nothing to create.
      await touchDraftTimes(linkUid, startISO ?? undefined, endISO ?? undefined);
      rescheduledIds = [];
      rescheduleReason = 'auto-send disabled — draft only, awaiting host send';
    }

    await upsertCalendarLink({
      iCalUid: linkUid,
      sequence: event.sequence,
      source: event.source,
      organizerEmail: event.organizer?.email,
      invitationIds: rescheduledIds,
      status: 'active',
      eventStart: startISO,
      eventEnd: endISO,
      providerEventId: event.providerEventId,
      draftAuthoritative: !!existing.draft_authoritative,
    });
    if (rescheduledIds.length === 0) {
      return { status: 'skipped', reason: rescheduleReason ?? 'reschedule produced no invites', iCalUid: linkUid, invitationIds: [] };
    }
    await emitIngested(event, tenantId, rescheduledIds, 'created');
    return { status: 'updated', reason: 'rescheduled', iCalUid: linkUid, invitationIds: rescheduledIds };
  }

  // ── New event ──
  // No auto-send (product decision 2026-06-17): passive producers build a Visit
  // Draft for the host to curate + send from the add-on. Invites are created only
  // via /addon/send (or the draft-authoritative reschedule above, for sent passes).
  // No calendar_event_links row is written here — that ledger is for sent events.
  const drafted = await draftFromEvent(event, domains, tenantId);
  await emitIngested(event, tenantId, [], drafted.drafted ? 'drafted' : 'skipped');
  return {
    status: drafted.drafted ? 'drafted' : 'skipped',
    reason: drafted.reason,
    iCalUid: uid,
    invitationIds: [],
  };
}

/**
 * No-auto-send model (2026-06-17): classify attendees and build (or refresh) the
 * Visit Draft for the host to curate + send in the add-on. Does NOT create invites.
 * Returns `drafted: false` with a reason when the event isn't an in-person visit.
 */
async function draftFromEvent(
  event: NormalizedCalendarEvent,
  domains: string[],
  tenantId: string,
): Promise<{ drafted: boolean; reason?: string }> {
  const { host, visitors } = classifyAttendees(event, domains);

  if (!host?.email) return { drafted: false, reason: 'no organizer/host' };
  // Host must be internal — otherwise this is an outside party inviting our
  // mailbox, not an employee hosting a visit. Forgery/irrelevance guard.
  if (domains.length && !domains.includes(domainOf(host.email))) {
    return { drafted: false, reason: `organizer ${host.email} not on an internal domain` };
  }
  if (visitors.length === 0) {
    return { drafted: false, reason: 'no external attendees (not an in-person visit)' };
  }

  // Build the draft from the classified visitors (host already excluded). Non-
  // destructive: getOrCreateDraft keeps any roster the host has already curated.
  await getOrCreateDraft({
    iCalUid: event.iCalUid,
    tenantId,
    providerEventId: event.providerEventId,
    title: event.title,
    hostEmail: host.email,
    attendees: visitors,
    eventStart: event.start?.toISOString(),
    eventEnd: event.end?.toISOString(),
    location: event.location,
  });
  // Keep times fresh on redelivery/reschedule without clobbering host roster edits.
  await touchDraftTimes(event.iCalUid, event.start?.toISOString(), event.end?.toISOString());
  return { drafted: true };
}

// ─── Automation surface (typed emit point, single drop-in) ────
// Per CLAUDE.md "build for the automation surface": one clear emit per state
// transition with a typed payload. NOT registered as a flow-pack trigger yet.

interface CalendarIngestedPayload extends Record<string, unknown> {
  tenantId: string;
  iCalUid: string;
  source: CalendarEventSource;
  outcome: 'created' | 'cancelled' | 'drafted' | 'skipped';
  invitationIds: string[];
  title?: string;
  organizerEmail?: string;
  visitorEmails: string[];
}

async function emitIngested(
  event: NormalizedCalendarEvent,
  tenantId: string,
  invitationIds: string[],
  outcome: 'created' | 'cancelled' | 'drafted' | 'skipped',
): Promise<void> {

