1	/**
2	 * Content script on Google Calendar — the DOM layer of the hybrid model.
3	 *
4	 * It reads the open event surface (detail popover / expanded edit) to:
5	 *  - GATE the "Manage Visitors" button on the magic address being a guest,
6	 *  - capture the `data-eventid` (base64url "<eventId> <calendarId>"), and
7	 *  - take a best-effort SNAPSHOT (guest emails) so the panel can paint instantly
8	 *    and cover the unsaved (no-API) case.
9	 * The API layer (background) remains the authoritative source. We read only the
10	 * semantic `data-eventid`, the `[role="dialog"]` ARIA signal, and the surface's
11	 * visible text — no layout/CSS-class coupling, no injection into Google's markup.
12	 */
13	import { MAGIC_ADDRESS } from '@/lib/config';
14	import {
15	  ACTIVE_EID_KEY,
16	  ACTIVE_SNAPSHOT_KEY,
17	  NUDGE_TARGETS,
18	  PANEL_STATE,
19	} from '@/lib/messaging';
20	import type { DomEventSnapshot, VisitorEventSummary } from '@/lib/types';
21	
22	export default defineContentScript({
23	  matches: ['https://calendar.google.com/*'],
24	  main() {
25	    // The id of the most recently clicked event chip — the event whose popover
26	    // is opening. Reset when the surface closes so a later unrelated dialog
27	    // can't resurrect a stale button.
28	    let clickedEid: string | null = null;
29	    let lastSnapshot: DomEventSnapshot | null = null;
30	    let panelOpen = false;
31	    let followedEid: string | null = null; // last event auto-pushed to the panel
32	    let pendingMagic: { eid: string; eventId: string; title: string } | null = null;
33	    let everSawEventId = false;
34	
35	    // Button UI: a native injected button when a clean anchor exists, else a
36	    // floating fallback (Idea 2). The magic-address gate is dropped — the button
37	    // shows on any open event surface; clicking it IS the intent.
38	    const button = createButtonUI(() => {
39	      if (!lastSnapshot) return;
40	      openFor(lastSnapshot); // opens the panel + sets the active event
41	      // Take the user to the full EDIT screen for this event — unless they're
42	      // already on it (avoid a reload that would drop unsaved edits). The
43	      // snapshot eid (from data-eventid) is already the right /eventedit eid.
44	      if (lastSnapshot.eid && !urlEid()) {
45	        chrome.runtime
46	          .sendMessage({ type: 'NAVIGATE_TO_EVENT', eid: lastSnapshot.eid })
47	          .catch(() => {});
48	      }
49	    });
50	
51	    // In-page nudge banner: visitor events the user saved but hasn't acted on.
52	    // Driven by the background sync (robust), not live DOM scanning.
53	    const nudge = mountNudge();
54	    chrome.runtime
55	      .sendMessage({ type: 'GET_NUDGE_TARGETS' })
56	      .then((res) => {
57	        if (res?.ok) nudge.setTargets(res.data as VisitorEventSummary[]);
58	      })
59	      .catch(() => {});
60	
61	    // Seed the panel-open state on (re)load so auto-follow works after a
62	    // same-tab navigation (the panel persists; this content script is fresh).
63	    chrome.runtime
64	      .sendMessage({ type: 'GET_PANEL_STATE' })
65	      .then((res) => {
66	        if (res?.ok) {
67	          panelOpen = !!(res.data as { open: boolean }).open;
68	          nudge.setPanelOpen(panelOpen);
69	          render();
70	        }
71	      })
72	      .catch(() => {});
73	
74	    // Fast detection: sync on load, on tab focus, and right after leaving the
75	    // event editor (a likely save) — so the banner appears in seconds, not up
76	    // to a minute, and shows immediately when the user returns to the tab.
77	    let lastSync = 0;
78	    const syncNow = () => {
79	      const now = Date.now();
80	      if (now - lastSync < 4000) return; // throttle
81	      lastSync = now;
82	      chrome.runtime.sendMessage({ type: 'SYNC_NOW' }).catch(() => {});
83	    };
84	    // Burst: fire several syncs after a likely save to beat Google's API
85	    // eventual-consistency lag (a fresh events.list may not show the just-saved
86	    // event for a few seconds).
87	    let lastBurst = 0;
88	    const syncBurst = () => {
89	      const now = Date.now();
90	      if (now - lastBurst < 2000) return;
91	      lastBurst = now;
92	      for (const d of [0, 3000, 8000]) {
93	        setTimeout(() => chrome.runtime.sendMessage({ type: 'SYNC_NOW' }).catch(() => {}), d);
94	      }
95	    };
96	    syncNow();
97	    document.addEventListener('visibilitychange', () => {
98	      if (document.visibilityState === 'visible') syncNow();
99	    });
100	    window.addEventListener('focus', syncNow);
101	    let wasEditor = /\/eventedit/.test(location.pathname);
102	    setInterval(() => {
103	      const isEditor = /\/eventedit/.test(location.pathname);
104	      if (wasEditor && !isEditor) syncBurst(); // left the editor → likely saved
105	      wasEditor = isEditor;
106	    }, 1000);
107	
108	    /** Read the open event surface, or null if none is open. `eid` may be '' for
109	     *  a brand-new, not-yet-saved event (no data-eventid / URL eid yet). */
110	    function readSurface(): { el: HTMLElement; eid: string } | null {
111	      const fromUrl = urlEid();
112	      const dialog = document.querySelector('[role="dialog"]') as HTMLElement | null;
113	      if (fromUrl) {
114	        return { el: dialog ?? document.body, eid: fromUrl };
115	      }
116	      // Full-screen create/edit editor (new event has no eid → eid '').
117	      if (/\/eventedit/.test(location.pathname)) {
118	        return { el: dialog ?? document.body, eid: clickedEid ?? '' };
119	      }
120	      // Detail / quick-create popover.
121	      if (dialog) return { el: dialog, eid: clickedEid ?? '' };
122	      return null;
123	    }
124	
125	    function snapshotOf(el: HTMLElement, eid: string): DomEventSnapshot {
126	      const text = el.innerText || '';
127	      const lower = text.toLowerCase();
128	      const magicPresent = !!MAGIC_ADDRESS && lower.includes(MAGIC_ADDRESS);
129	      const guestEmails = extractEmails(text).filter(
130	        (e) => e.toLowerCase() !== MAGIC_ADDRESS,
131	      );
132	      // Best-effort title (cosmetic — the API sync replaces it). The editor's
133	      // title is a text input; fall back to undefined.
134	      const titleInput = el.querySelector(
135	        'input[aria-label*="title" i], input[placeholder*="title" i]',
136	      ) as HTMLInputElement | null;
137	      const title = titleInput?.value?.trim() || undefined;
138	      return { eid, magicPresent, guestEmails, title };
139	    }
140	
141	    function render() {
142	      const surface = readSurface();
143	      lastSnapshot = surface ? snapshotOf(surface.el, surface.eid) : null;
144	
145	      // Instant nudge: while viewing a visitor event WITH a real eid, remember
146	      // it; when the user then leaves that surface (closed popover / saved &
147	      // left editor), show the nudge for it IMMEDIATELY — no API round-trip.
148	      if (lastSnapshot?.magicPresent && lastSnapshot.eid) {
149	        pendingMagic = {
150	          eid: lastSnapshot.eid,
151	          eventId: decodeEventId(lastSnapshot.eid),
152	          title: lastSnapshot.title ?? '',
153	        };
154	      } else if (!surface && pendingMagic) {
155	        nudge.addOptimistic({
156	          eid: pendingMagic.eid,
157	          eventId: pendingMagic.eventId,
158	          iCalUid: '',
159	          title: pendingMagic.title,
160	          start: undefined,
161	        });
162	        syncBurst(); // confirm/refresh from the API right after
163	        pendingMagic = null;
164	      }
165	
166	      // Panel closed → show the button on any open event surface.
167	      // Panel open → hide the button and auto-follow the saved event in view.
168	      if (panelOpen) {
169	        button.update(false);
170	        maybeFollow();
171	      } else {
172	        button.update(!!surface);
173	      }
174	    }
175	
176	    /** Push the open *saved* event to the panel so it follows what you're viewing.
177	     *  Saved only (non-empty eid); deduped; the panel guards against switching
178	     *  mid-action. */
179	    function maybeFollow() {
180	      const snap = lastSnapshot;
181	      if (!snap || !snap.eid) return; // new/unsaved events don't auto-switch
182	      if (snap.eid === followedEid) return;
183	      followedEid = snap.eid;
184	      chrome.runtime
185	        .sendMessage({ type: 'FOLLOW_EVENT', eid: snap.eid, snapshot: snap })
186	        .catch(() => {});
187	    }
188	
189	    document.addEventListener(
190	      'click',
191	      (e) => {
192	        const chip = (e.target as Element | null)?.closest?.('[data-eventid]');
193	        const id = chip?.getAttribute('data-eventid');
194	        if (id) {
195	          everSawEventId = true;
196	          clickedEid = id;
197	        }
198	        setTimeout(render, 60); // let the popover render
199	      },
200	      true,
201	    );
202	
203	    document.addEventListener(
204	      'keydown',
205	      (e) => {
206	        if (e.key === 'Escape') {
207	          clickedEid = null;
208	          setTimeout(render, 60);
209	        }
210	      },
211	      true,
212	    );
213	
214	    // Detect surface open/close + edits (e.g. adding the magic address live).
215	    let timer: number | undefined;
216	    new MutationObserver(() => {
217	      clearTimeout(timer);
218	      timer = setTimeout(() => {
219	        if (!document.querySelector('[role="dialog"]') && !urlEid()) {
220	          clickedEid = null;
221	        }
222	        render();
223	      }, 150) as unknown as number;
224	    }).observe(document.body, { childList: true, subtree: true });
225	
226	    window.addEventListener('popstate', render);
227	
228	    // Hide the in-page button while the side panel is open.
229	    chrome.runtime.onMessage.addListener(
230	      (msg: { type?: string; open?: boolean; targets?: VisitorEventSummary[] }) => {
231	        if (msg?.type === PANEL_STATE) {
232	          panelOpen = !!msg.open;
233	          if (!panelOpen) followedEid = null; // re-follow next time it opens
234	          nudge.setPanelOpen(panelOpen); // banner hides while the panel is open
235	          render();
236	        } else if (msg?.type === NUDGE_TARGETS) {
237	          nudge.setTargets(msg.targets ?? []);
238	        }
239	      },
240	    );
241	
242	    setTimeout(() => {
243	      if (!everSawEventId && !document.querySelector('[data-eventid]')) {
244	        console.warn(
245	          '[auxilio] no [data-eventid] found — click detection may be unavailable; use the panel’s event list.',
246	        );
247	      }
248	    }, 90_000);
249	
250	    render();
251	    console.log('[auxilio] content script ready on Google Calendar');
252	  },
253	});
254	
255	function openFor(snapshot: DomEventSnapshot) {
256	  return chrome.runtime
257	    .sendMessage({ type: 'OPEN_FOR_EVENT', eid: snapshot.eid, snapshot })
258	    .catch((err) => console.error('[auxilio] open failed', err));
259	}
260	
261	/** Event id from the expanded-edit URL path, if present. */
262	function urlEid(): string | null {
263	  const path = location.pathname.match(/\/eventedit\/([^/?#]+)/);
264	  if (path && path[1] !== 'eventedit') return safeDecode(path[1]);
265	  const q = new URLSearchParams(location.search).get('eid');
266	  return q ? safeDecode(q) : null;
267	}
268	
269	/** Pull unique email-looking strings from text (best-effort guest scrape). */
270	function extractEmails(text: string): string[] {
271	  const matches = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) ?? [];
272	  return [...new Set(matches.map((m) => m.toLowerCase()))];
273	}
274	
275	/** eid (base64url of "<eventId> <calendarId>") → eventId, for nudge dedup. */
276	function decodeEventId(eid: string): string {
277	  try {
278	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
279	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
280	    return atob(b64).split(' ')[0] || '';
281	  } catch {
282	    return '';
283	  }
284	}
285	
286	function safeDecode(s: string): string {
287	  try {
288	    return decodeURIComponent(s);
289	  } catch {
290	    return s;
291	  }
292	}
293	
294	const USERS_SVG = `
295	<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24"
296	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
297	  <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
298	  <path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>`;
299	
300	const LABEL = 'Manage Visitors';
301	const INJECT_ID = 'auxilio-manage-visitors';
302	
303	/**
304	 * Button UI manager (Idea 2): renders a NATIVE-styled button injected at a clean
305	 * anchor (next to Save on the /eventedit page) when one is found, and otherwise
306	 * falls back to a floating button. `update(show)` decides per render.
307	 */
308	function createButtonUI(onClick: () => void) {
309	  const fab = mountFloating(onClick);
310	  let injected: HTMLButtonElement | null = null;
311	
312	  /** A clean injection anchor, or null. Text/ARIA-based, never CSS classes. */
313	  function findAnchor(): { insert: (el: HTMLElement) => void } | null {
314	    // Edit page: place our button right before the native "Save" button.
315	    if (/\/eventedit/.test(location.pathname)) {
316	      const save = findButtonByText('save');
317	      const parent = save?.parentElement;
318	      if (save && parent) {
319	        return { insert: (el) => parent.insertBefore(el, save) };
320	      }
321	    }
322	    return null; // popover/modal → fall back to floating
323	  }
324	
325	  function ensureInjected(): boolean {
326	    const anchor = findAnchor();
327	    if (!anchor) return false;
328	    if (injected && injected.isConnected) return true; // still placed
329	    removeInjected();
330	    injected = buildInjectedButton(onClick);
331	    anchor.insert(injected);
332	    return true;
333	  }
334	
335	  function removeInjected() {
336	    injected?.remove();
337	    injected = null;
338	  }
339	
340	  return {
341	    update(show: boolean) {
342	      if (!show) {
343	        removeInjected();
344	        fab.setVisible(false);
345	        return;
346	      }
347	      const placed = ensureInjected();
348	      fab.setVisible(!placed); // floating only when we couldn't inject natively
349	    },
350	  };
351	}
352	
353	/** Find a clickable element whose visible text matches (case-insensitive). */
354	function findButtonByText(text: string): HTMLElement | null {
355	  const wanted = text.toLowerCase();
356	  const els = document.querySelectorAll<HTMLElement>('button,[role="button"]');
357	  for (const el of els) {
358	    if ((el.textContent ?? '').trim().toLowerCase() === wanted) return el;
359	  }
360	  return null;
361	}
362	
363	/** Stop our interactions dismissing Google's modal / triggering its buttons. */
364	function shieldInteractions(el: HTMLElement) {
365	  for (const type of ['pointerdown', 'mousedown', 'touchstart'] as const) {
366	    el.addEventListener(
367	      type,
368	      (e) => {
369	        e.stopPropagation();
370	        e.preventDefault(); // don't move focus out of the Calendar dialog
371	      },
372	      true,
373	    );
374	  }
375	  el.addEventListener('click', (e) => e.stopPropagation(), true);
376	}
377	
378	/** Native-styled (light-DOM) button inserted into Google's edit page. */
379	function buildInjectedButton(onClick: () => void): HTMLButtonElement {
380	  const btn = document.createElement('button');
381	  btn.id = INJECT_ID;
382	  btn.type = 'button';
383	  btn.style.cssText = [
384	    'display:inline-flex',
385	    'align-items:center',
386	    'gap:8px',
387	    "font-family:'Google Sans','Roboto',system-ui,sans-serif",
388	    'font-size:14px',
389	    'font-weight:600',
390	    'color:#fff',
391	    'background:#92288e',
392	    'border:none',
393	    'border-radius:999px',
394	    'padding:8px 16px',
395	    'margin-right:8px',
396	    'cursor:pointer',
397	  ].join(';');
398	  btn.innerHTML = `${USERS_SVG}<span>${LABEL}</span>`;
399	  shieldInteractions(btn);
400	  wireActivate(btn, onClick);
401	  return btn;
402	}
403	
404	/** Floating fallback button (shadow-DOM, fully isolated). */
405	function mountFloating(onClick: () => void) {
406	  const host = document.createElement('div');
407	  host.style.cssText = 'position:fixed;right:24px;bottom:24px;z-index:2147483646;';
408	  document.documentElement.appendChild(host);
409	  const root = host.attachShadow({ mode: 'open' });
410	  root.innerHTML = `
411	    <style>
412	      :host { all: initial; }
413	      .fab {
414	        display:inline-flex;align-items:center;gap:8px;
415	        font-family:'Google Sans','Roboto',system-ui,sans-serif;font-size:14px;font-weight:600;
416	        color:#fff;background:#92288e;border:none;border-radius:999px;padding:12px 18px;
417	        box-shadow:0 2px 6px rgba(0,0,0,.18);cursor:pointer;
418	        transform:translateY(8px);opacity:0;pointer-events:none;
419	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1),box-shadow 120ms ease;
420	      }
421	      .fab.show{opacity:1;transform:none;pointer-events:auto;}
422	      .fab:hover{box-shadow:0 4px 12px rgba(0,0,0,.24);}
423	      .fab:active{transform:scale(.98);}
424	      .fab[disabled]{opacity:.6;pointer-events:none;}
425	      @media (prefers-reduced-motion: reduce){.fab{transition:none;transform:none;}}
426	    </style>
427	    <button class="fab" type="button">${USERS_SVG}<span class="label">${LABEL}</span></button>`;
428	  const btn = root.querySelector('button') as HTMLButtonElement;
429	  shieldInteractions(host);
430	  wireActivate(btn, onClick);
431	  return {
432	    setVisible(v: boolean) {
433	      btn.classList.toggle('show', v);
434	    },
435	  };
436	}
437	
438	/** Shared activate handler (pointerup + click, double-fire-guarded). */
439	function wireActivate(btn: HTMLButtonElement, onClick: () => void) {
440	  const label = btn.querySelector('span:last-of-type') as HTMLSpanElement | null;
441	  let firing = false;
442	  const activate = async () => {
443	    if (firing) return;
444	    firing = true;
445	    btn.disabled = true;
446	    const prev = label?.textContent;
447	    if (label) label.textContent = 'Opening…';
448	    try {
449	      await onClick();
450	    } finally {
451	      btn.disabled = false;
452	      if (label && prev) label.textContent = prev;
453	      firing = false;
454	    }
455	  };
456	  btn.addEventListener('pointerup', activate);
457	  btn.addEventListener('click', activate);
458	}
459	
460	const NUDGE_DISMISS_KEY = 'auxilio.dismissedNudges';
461	const BELL_SVG = `
462	<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24"
463	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
464	  <path d="M10.268 21a2 2 0 0 0 3.464 0"/><path d="M3.262 15.326A1 1 0 0 0 4 17h16a1 1 0 0 0 .74-1.673C19.41 13.956 18 12.499 18 8A6 6 0 0 0 6 8c0 4.499-1.411 5.956-2.738 7.326"/></svg>`;
465	const NUDGE_X_SVG = `
466	<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24"
467	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
468	  <path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>`;
469	
470	/**
471	 * In-page nudge banner (sync-driven). Shows the soonest visitor event the user
472	 * saved but hasn't acted on. "Manage" opens the panel AND navigates this tab to
473	 * the event — one click opens both. Dismissals persist in storage.session.
474	 */
475	function mountNudge() {
476	  const host = document.createElement('div');
477	  host.style.cssText =
478	    'position:fixed;top:72px;left:50%;transform:translateX(-50%);z-index:2147483647;';
479	  document.documentElement.appendChild(host);
480	  const root = host.attachShadow({ mode: 'open' });
481	  root.innerHTML = `
482	    <style>
483	      :host { all: initial; }
484	      .banner {
485	        display:flex;align-items:center;gap:12px;max-width:520px;
486	        font-family:'Google Sans','Roboto',system-ui,sans-serif;color:#310031;
487	        background:#f8d9f5;border:1px solid #92288e33;border-radius:14px;
488	        padding:10px 12px 10px 16px;box-shadow:0 4px 12px rgba(0,0,0,.18);
489	        transform:translateY(-12px);opacity:0;pointer-events:none;
490	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1);
491	      }
492	      .banner.show{opacity:1;transform:none;pointer-events:auto;}
493	      .icon{display:inline-flex;color:#92288e;flex:0 0 auto;}
494	      .text{font-size:13.5px;line-height:18px;}
495	      .text b{font-weight:600;}
496	      .actions{display:flex;align-items:center;gap:4px;flex:0 0 auto;}
497	      .manage{font:inherit;font-size:13px;font-weight:600;color:#fff;background:#92288e;
498	        border:none;border-radius:999px;padding:8px 14px;cursor:pointer;}
499	      .manage:hover{box-shadow:0 2px 6px rgba(0,0,0,.2);}
500	      .dismiss{display:inline-flex;align-items:center;justify-content:center;width:30px;height:30px;
501	        border:none;border-radius:50%;background:transparent;color:#5f5560;cursor:pointer;}
502	      .dismiss:hover{background:#0000000f;}
503	      @media (prefers-reduced-motion: reduce){.banner{transition:none;transform:none;}}
504	    </style>
505	    <div class="banner">
506	      <span class="icon">${BELL_SVG}</span>
507	      <span class="text"></span>
508	      <span class="actions">
509	        <button class="manage" type="button">Manage</button>
510	        <button class="dismiss" type="button" aria-label="Dismiss">${NUDGE_X_SVG}</button>
511	      </span>
512	    </div>`;
513	  const wrap = root.querySelector('.banner') as HTMLDivElement;
514	  const text = root.querySelector('.text') as HTMLSpanElement;
515	  const manageBtn = root.querySelector('.manage') as HTMLButtonElement;
516	  const dismissBtn = root.querySelector('.dismiss') as HTMLButtonElement;
517	  shieldInteractions(host);
518	
519	  let targets: VisitorEventSummary[] = [];
520	  // Optimistic, DOM-derived targets shown INSTANTLY (no API wait) for an event
521	  // the user just interacted with; the API sync reconciles them by eventId.
522	  const optimistic = new Map<string, VisitorEventSummary>();
523	  let panelOpen = false;
524	  let dismissed = new Set<string>();
525	  let current: VisitorEventSummary | null = null;
526	
527	  chrome.storage.session.get(NUDGE_DISMISS_KEY).then((r) => {
528	    dismissed = new Set((r[NUDGE_DISMISS_KEY] as string[]) ?? []);
529	    render();
530	  });
531	
532	  /** Merged, deduped, soonest-first (synced target wins over optimistic). */
533	  function merged(): VisitorEventSummary[] {
534	    const byId = new Map<string, VisitorEventSummary>();
535	    for (const o of optimistic.values()) byId.set(o.eventId, o);
536	    for (const t of targets) byId.set(t.eventId, t); // synced data wins
537	    return [...byId.values()].sort((a, b) =>
538	      (a.start ?? '~').localeCompare(b.start ?? '~'),
539	    );
540	  }
541	
542	  function visible(): VisitorEventSummary | null {
543	    return merged().find((t) => !dismissed.has(t.eventId)) ?? null;
544	  }
545	
546	  function render() {
547	    const t = panelOpen ? null : visible();
548	    current = t;
549	    if (!t) {
550	      wrap.classList.remove('show');
551	      return;
552	    }
553	    const more = merged().filter((x) => !dismissed.has(x.eventId)).length - 1;
554	    text.innerHTML =
555	      `<b>Visitor event needs passes.</b> ${escapeText(t.title || '')}` +
556	      (more > 0 ? ` <span style="opacity:.7">+${more} more</span>` : '');
557	    wrap.classList.add('show');
558	  }
559	
560	  // Use pointerup (not click): the host's capture-phase shield — which stops our
561	  // interactions from dismissing Google's modal — would otherwise swallow click.
562	  manageBtn.addEventListener('pointerup', () => {
563	    if (!current) return;
564	    const target = current;
565	    manageBtn.disabled = true;
566	    manageBtn.textContent = 'Opening…';
567	    // Engaging with the event clears its nudge for the session, so it doesn't
568	    // reappear when the panel closes (or when the optimistic re-add fires).
569	    dismissed.add(target.eventId);
570	    chrome.storage.session.set({ [NUDGE_DISMISS_KEY]: [...dismissed] }).catch(() => {});
571	    render(); // hide the banner now
572	    // Set the active event FIRST (storage.session, now content-accessible) so the
573	    // panel has it the moment it mounts — no dependence on message ordering.
574	    chrome.storage.session
575	      .set({ [ACTIVE_EID_KEY]: target.eid, [ACTIVE_SNAPSHOT_KEY]: null })
576	      .catch(() => {});
577	    // Open the panel immediately within this gesture (don't await first).
578	    chrome.runtime.sendMessage({ type: 'OPEN_FOR_EVENT', eid: target.eid }).catch(() => {});
579	    // Bring this tab to the event's edit page (prefer the real eid when present).
580	    chrome.runtime
581	      .sendMessage({ type: 'NAVIGATE_TO_EVENT', eid: target.eid, eventId: target.eventId })
582	      .catch(() => {})
583	      .finally(() => {
584	        manageBtn.disabled = false;
585	        manageBtn.textContent = 'Manage';
586	      });
587	  });
588	
589	  dismissBtn.addEventListener('pointerup', () => {
590	    if (!current) return;
591	    dismissed.add(current.eventId);
592	    chrome.storage.session.set({ [NUDGE_DISMISS_KEY]: [...dismissed] }).catch(() => {});
593	    render();
594	  });
595	
596	  return {
597	    setTargets(next: VisitorEventSummary[]) {
598	      targets = next ?? [];
599	      // Drop optimistic entries the real sync now covers.
600	      for (const t of targets) optimistic.delete(t.eventId);
601	      render();
602	    },
603	    addOptimistic(s: VisitorEventSummary) {
604	      optimistic.set(s.eventId, s);
605	      render();
606	    },
607	    setPanelOpen(open: boolean) {
608	      panelOpen = open;
609	      render();
610	    },
611	  };
612	}
613	
614	function escapeText(s: string): string {
615	  const d = document.createElement('div');
616	  d.textContent = s;
617	  return d.innerHTML;
618	}
